// Get GPU/WebGL info

const getWebglInfo = () => {
  const gl = store.gl.backend.gl;
  const debugInfo = gl.getExtension("WEBGL_debug_renderer_info");
  const vendor = gl.getParameter(debugInfo.UNMASKED_VENDOR_WEBGL);
  const renderer = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL);
  return { vendor, renderer };
};

async function getRendererInfo() {
  if (store.isWebGPU) {
    try {
      const adapter = await navigator.gpu.requestAdapter();
      if (adapter === null) {
        return "Unable to create WebGPU adapter";
      }

      const { vendor, architecture, device, description } = adapter.info;
      return `
        Vendor: ${vendor}
        Architecture: ${architecture}
  ${device ? `Device: ${device}` : ""}
  ${description ? `Description: ${description}` : ""}`;
    } catch (error) {
      return `Error getting WebGPU info: ${error.message}`;
    }
  } else {
    try {
      const { vendor, renderer } = getWebglInfo();
      return `
        Vendor: ${vendor}
        Renderer: ${renderer}`;
    } catch (error) {
      return `Error getting WebGL info: ${error.message}`;
    }
  }
}

const debugInfo = async () => {
  const threadType =
    typeof window === "undefined"
      ? "WORKER THREAD (OffScreenCanvas)"
      : "MAIN THREAD";
  const renderBackend = store.isWebGPU ? "WebGPU" : "WebGL";
  const hardwareInfo = await getRendererInfo();

  dispatcherSingleton.trigger(
    { name: "debugInfos" },
    {
      threadType,
      renderBackend,
      hardwareInfo,
    }
  );
};

// Orthographic camera sees everything in its box - no perspective culling
const compileCamera = new OrthographicCamera(
  -1e10,
  1e10, // left, right
  1e10,
  -1e10, // top, bottom
  -1e10,
  1e10 // near (negative = behind), far
);

// Negative near plane means it sees objects "behind" it too
compileCamera.updateMatrixWorld();
compileCamera.updateProjectionMatrix();

async function compileScene(gl, scene, camera = compileCamera) {
  const original = new WeakMap();
  const originalPerObject = new WeakMap();
  const invisibleOriginal = new WeakMap();

  scene.traverse((obj) => {
    if (obj.frustumCulled) {
      original.set(obj, true);
      obj.frustumCulled = false;
    }

    if (obj.perObjectFrustumCulled) {
      originalPerObject.set(obj, true);
      obj.perObjectFrustumCulled = false;
    }

    if (obj.visible === false) {
      invisibleOriginal.set(obj, true);
      obj.visible = true;
    }
  });

  await gl.compileAsync(scene, camera);

  scene.traverse((obj) => {
    if (original.has(obj)) obj.frustumCulled = true;
    if (invisibleOriginal.has(obj)) obj.visible = false;
    if (originalPerObject.has(obj)) obj.perObjectFrustumCulled = true;
  });
}

// Camera component allowing automatic orbit control override and such
class CameraOrbitController {
  constructor(instance) {
    this.translation = new Vector3();
    this.target = new Vector3();
    this.cameraOffset = new Vector3();
    this.cameraOffset2 = new Vector3();
    this.targetOffset = new Vector3();
    this.targetOffset2 = new Vector3();

    this.distance = new Vector2();
    this.distanceDamp = new Vector2();
    this.mouseLast = new Vector2();
    this.mouse = new Vector2();
    this.velocity = new Vector2();

    this.followCamera = true;

    this.mousePanning = new Vector2(0.005, 0.001);

    this.cameraRoll = 0;
    this._rollQuaternion = new Quaternion();
    this._tempQuaternion = new Quaternion();

    this.controls = new OrbitControls(
      instance.camera,
      instance.renderer.domElement
    );
    this.controls.cameraMix = 1;
    this.mixActive = true;

    this.controls.enableDamping = false;
    this.controls.dampingFactor = 0.05;
    this.friction = 0.99;
    this.controls.screenSpacePanning = false;
    this.controls.enableZoom = false;

    this.controls.enablePan = false;
    this.controls.enableRotate = false;

    // Keyboard events only work in main thread, skip in worker
    if (typeof window !== 'undefined') {
      this.controls.listenToKeyEvents(window);
    }

    this.camera = instance.camera;

    this.controls.maxPolarAngle = Math.PI;
    this.controls.minPolarAngle = 0;
    this.controls.maxDistance = 2000;
  }

  dispose() {
    this.controls.dispose();
  }

  /**
   * Update camera position and target from spline system
   */
  updateFromSpline(splinePosition, splineTarget, splineRoll = 0) {
    if (splinePosition) {
      this.translation.copy(splinePosition);
    }
    if (splineTarget) {
      this.target.copy(splineTarget);
    }
    this.cameraRoll = splineRoll;
  }

  onRaf({ time, delta }) {
    this.mouse.x = pointer.normalized.x;
    this.mouse.y = pointer.normalized.y;

    this.distance.x = -(this.mouse.x - this.mouseLast.x) * this.mousePanning.x;
    this.distance.y = (this.mouse.y - this.mouseLast.y) * this.mousePanning.y;

    this.velocity.x = this.velocity.x * this.friction + this.distance.x;
    this.velocity.y = this.velocity.y * this.friction - this.distance.y;

    this.controls.rotationOffset.x = this.velocity.x;
    this.controls.rotationOffset.y = this.velocity.y;

    this.mouseLast.x = this.mouse.x;
    this.mouseLast.y = this.mouse.y;

    this.controls.target.x =
      this.target.x + this.targetOffset.x + this.targetOffset2.x;
    this.controls.target.y =
      this.target.y + this.targetOffset.y + this.targetOffset2.y;
    this.controls.target.z =
      this.target.z + this.targetOffset.z + this.targetOffset2.z;

    this.controls.translation.x =
      this.translation.x + this.cameraOffset.x + this.cameraOffset2.x;
    this.controls.translation.y =
      this.translation.y + this.cameraOffset.y + this.cameraOffset2.y;
    this.controls.translation.z =
      this.translation.z + this.cameraOffset.z + this.cameraOffset2.z;

    if (this.followCamera) {
      this.controls.updateFromExternalChanges(delta);
    }

    this.controls.update(delta);

    // Apply camera roll (rotation around the view axis/Z-axis)
    // This rotates the camera around its forward-facing direction
    if (this.cameraRoll !== 0) {
      // Get the camera's current forward direction (view axis)
      const viewDirection = new Vector3(0, 0, -1);
      viewDirection.applyQuaternion(this.camera.quaternion);

      // Create a quaternion for rotation around the view axis
      this._rollQuaternion.setFromAxisAngle(viewDirection, this.cameraRoll);

      // Apply the roll rotation to the camera
      this._tempQuaternion.copy(this.camera.quaternion);
      this.camera.quaternion.copy(
        this._rollQuaternion.multiply(this._tempQuaternion)
      );
    }
  }

  onReset() {
    this.controls.reset();
  }

  onResize({ ratio }) {}
}

/**
 * CameraSplineSystem - Manages camera and target spline paths
 * Integrates with Theatre.js for animation control
 * Supports TransformControls for editing spline points in debug mode
 */
class CameraSplineSystem {
  constructor({
    scene,
    camera,
    renderer,
    sceneKey,
    theatreSheet,
    mainTheatreSheet,
    multiSceneCompositor,
    debugScaleFactor = 1.0
  }) {
    this.scene = scene;
    this.camera = camera;
    this.renderer = renderer;
    this.sceneKey = sceneKey;
    this.theatreSheet = theatreSheet;
    this.mainTheatreSheet = mainTheatreSheet;
    this.multiSceneCompositor = multiSceneCompositor;
    this.debugScaleFactor = debugScaleFactor;

    // Spline points for camera position and target
    this.cameraPoints = [];
    this.targetPoints = [];

    // Three.js curves
    this.cameraCurve = null;
    this.targetCurve = null;

    // Visual helpers (only in debug mode)
    this.cameraSplineHelper = null;
    this.targetSplineHelper = null;
    this.pointHelpers = [];

    // Target visualization (always visible)
    this.targetHelper = null;
    this.currentTarget = new Vector3();
    this.currentCameraPosition = new Vector3();

    // Transform controls for editing
    this.transformControls = null;
    this.selectedPoint = null;

    // Theatre.js object for animation control
    this.theatreObject = null;

    // Debug camera and controls
    this.debugCamera = null;
    this.debugOrbitControls = null;
    this.cameraHelper = null; // Helper to visualize the scene camera in debug mode
    this.isDebugMode = false;

    // Flag to indicate if orbit controller is managing the camera
    this.hasOrbitController = false;

    this.init();
  }

  async init() {
    // Create default spline points if none exist
    this.initializeDefaultPoints();

    // Create curves
    this.updateCurves();

    // Load debug tools if in dev mode
    if (isDebugEnabled()) {
      await this.initDebugTools();
    }

    // Setup Theatre.js integration
    this.setupTheatreIntegration();
  }

  /**
   * Initialize default spline points based on current camera position
   */
  initializeDefaultPoints() {
    // Get current camera position and target
    const cameraPos = this.camera.position.clone();
    const direction = new Vector3();
    this.camera.getWorldDirection(direction);
    const targetPos = cameraPos.clone().add(direction.multiplyScalar(10));

    // Create 4 points for each spline
    this.cameraPoints = [
      cameraPos.clone(),
      cameraPos.clone().add(new Vector3(2, 1, 0)),
      cameraPos.clone().add(new Vector3(4, 2, 1)),
      cameraPos.clone().add(new Vector3(6, 3, 2))
    ];

    this.targetPoints = [
      targetPos.clone(),
      targetPos.clone().add(new Vector3(2, 0, 0)),
      targetPos.clone().add(new Vector3(4, 0, 1)),
      targetPos.clone().add(new Vector3(6, 0, 2))
    ];
  }

  /**
   * Update the curves based on current points
   */
  updateCurves() {
    this.cameraCurve = new CatmullRomCurve3(this.cameraPoints);
    this.targetCurve = new CatmullRomCurve3(this.targetPoints);
  }

  /**
   * Initialize debug tools (only in development)
   */
  async initDebugTools() {
    const { TransformControls, OrbitControls } = await loadDebugTools();
    if (!TransformControls || !OrbitControls) return

    // Create camera spline helper
    const cameraPoints = this.cameraCurve.getPoints(50);
    const cameraGeometry = new BufferGeometry().setFromPoints(
      cameraPoints
    );
    const cameraMaterial = new LineBasicMaterial({ color: 0x00ff00 });
    this.cameraSplineHelper = new Line(cameraGeometry, cameraMaterial);
    this.scene.add(this.cameraSplineHelper);

    // Create target spline helper
    const targetPoints = this.targetCurve.getPoints(50);
    const targetGeometry = new BufferGeometry().setFromPoints(
      targetPoints
    );
    const targetMaterial = new LineBasicMaterial({ color: 0xff0000 });
    this.targetSplineHelper = new Line(targetGeometry, targetMaterial);
    this.scene.add(this.targetSplineHelper);

    // Create point helpers for camera points
    // Scale the sphere size based on debugScaleFactor for better visibility
    const sphereRadius = 0.2 * this.debugScaleFactor;

    this.cameraPoints.forEach((point, index) => {
      const geometry = new SphereGeometry(sphereRadius, 16, 16);
      const material = new MeshBasicMaterial({ color: 0x00ff00 });
      const sphere = new Mesh(geometry, material);
      sphere.position.copy(point);
      sphere.userData = { type: 'camera', index };
      this.pointHelpers.push(sphere);
      this.scene.add(sphere);
    });

    // Create point helpers for target points
    this.targetPoints.forEach((point, index) => {
      const geometry = new SphereGeometry(sphereRadius, 16, 16);
      const material = new MeshBasicMaterial({ color: 0xff0000 });
      const sphere = new Mesh(geometry, material);
      sphere.position.copy(point);
      sphere.userData = { type: 'target', index };
      this.pointHelpers.push(sphere);
      this.scene.add(sphere);
    });

    // Create debug camera
    // Scale near/far values by debugScaleFactor for large scenes
    this.debugCamera = new PerspectiveCamera(
      60,
      400 / 300, // Fixed aspect ratio for debug view
      0.1 * this.debugScaleFactor,
      1000 * this.debugScaleFactor
    );
    this.debugCamera.position.set(20, 10, 20);
    this.debugCamera.lookAt(0, 0, 0);

    // Create CameraHelper to visualize the scene camera
    this.cameraHelper = new CameraHelper(this.camera);
    this.scene.add(this.cameraHelper);

    // Create target visualization (small sphere at current target position)
    const targetSphereGeometry = new SphereGeometry(
      0.3 * this.debugScaleFactor,
      16,
      16
    );
    const targetSphereMaterial = new MeshBasicMaterial({
      color: 0xffff00,
      transparent: true,
      opacity: 0.8
    });
    this.targetHelper = new Mesh(
      targetSphereGeometry,
      targetSphereMaterial
    );
    this.scene.add(this.targetHelper);

    // Register scene with debug view manager
    const debugView = getDebugView();
    if (debugView) {
      await debugView.registerScene(this.sceneKey, this.scene, this.debugCamera);

      // Create TransformControls for the debug view
      if (TransformControls && debugView.canvas) {
        this.transformControls = new TransformControls(
          this.debugCamera,
          debugView.canvas
        );

        // Add dragging event to pause orbit controls
        this.transformControls.addEventListener('dragging-changed', (event) => {
          const sceneData = debugView.scenes.get(this.sceneKey);
          if (sceneData && sceneData.orbitControls) {
            sceneData.orbitControls.enabled = !event.value;
          }
        });

        // Add change event to update splines when transforming
        this.transformControls.addEventListener('change', () => {
          this.onPointTransformed();
        });

        // Add the TransformControls helper to the scene
        this.scene.add(this.transformControls.getHelper());

        // Register the controls and helpers with the debug view
        debugView.registerControls(
          this.sceneKey,
          this.transformControls,
          this.pointHelpers
        );
      }
    }

    // Configure layers: helpers only visible in debug view (layer 1)
    // Main camera sees layer 0 only, debug camera sees both layers
    this.cameraSplineHelper.layers.set(1);
    this.targetSplineHelper.layers.set(1);
    this.cameraHelper.layers.set(1);
    this.targetHelper.layers.set(1);

    // Set all point helpers to layer 1
    this.pointHelpers.forEach((helper) => {
      helper.layers.set(1);
    });

    // Set TransformControls helper to layer 1 if it exists
    if (this.transformControls) {
      const transformHelper = this.transformControls.getHelper();
      if (transformHelper) {
        transformHelper.layers.set(1);
      }
    }

    // Configure main camera to only see layer 0 (scene content)
    this.camera.layers.disableAll();
    this.camera.layers.enable(0);

    // Configure debug camera to see both layer 0 (scene) and layer 1 (helpers)
    this.debugCamera.layers.enableAll();
  }

  /**
   * Handle point transformation via TransformControls
   * This updates the spline points when dragging with TransformControls
   * and syncs changes to Theatre.js for saving
   */
  onPointTransformed() {
    // Get the currently attached object from TransformControls
    if (!this.transformControls || !this.transformControls.object) return

    const attachedObject = this.transformControls.object;
    const { type, index } = attachedObject.userData;

    if (type === 'camera') {
      // Update the camera point
      this.cameraPoints[index].copy(attachedObject.position);

      // Update Theatre.js values so changes can be saved
      if (this.cameraPointsObject) {
        const studio = getTheatreStudio();
        if (studio) {
          // Use studio transaction to update values - this makes them appear in Theatre.js UI
          studio.transaction(({ set }) => {
            set(
              this.cameraPointsObject.props[`cam${index}_x`],
              attachedObject.position.x
            );
            set(
              this.cameraPointsObject.props[`cam${index}_y`],
              attachedObject.position.y
            );
            set(
              this.cameraPointsObject.props[`cam${index}_z`],
              attachedObject.position.z
            );
          });
        }
      }
    } else if (type === 'target') {
      // Update the target point
      this.targetPoints[index].copy(attachedObject.position);

      // Update Theatre.js values so changes can be saved
      if (this.targetPointsObject) {
        const studio = getTheatreStudio();
        if (studio) {
          // Use studio transaction to update values - this makes them appear in Theatre.js UI
          studio.transaction(({ set }) => {
            set(
              this.targetPointsObject.props[`target${index}_x`],
              attachedObject.position.x
            );
            set(
              this.targetPointsObject.props[`target${index}_y`],
              attachedObject.position.y
            );
            set(
              this.targetPointsObject.props[`target${index}_z`],
              attachedObject.position.z
            );
          });
        }
      }
    }

    // Update curves and helpers
    this.updateCurves();
    this.updateSplineHelpers();

    // Update camera position if in non-debug mode
    if (!this.isDebugMode && this.theatreObject) {
      this.updateCameraFromProgress(
        this.theatreObject.value.cameraProgress,
        this.theatreObject.value.targetProgress
      );
    }
  }

  /**
   * Update spline helper visualization
   */
  updateSplineHelpers() {
    if (this.cameraSplineHelper) {
      const cameraPoints = this.cameraCurve.getPoints(50);
      this.cameraSplineHelper.geometry.setFromPoints(cameraPoints);
    }

    if (this.targetSplineHelper) {
      const targetPoints = this.targetCurve.getPoints(50);
      this.targetSplineHelper.geometry.setFromPoints(targetPoints);
    }
  }

  /**
   * Setup Theatre.js integration
   * Note: onValuesChange callbacks don't fire in web workers (offscreen mode),
   * so we also manually read values in onRaf() as a workaround.
   * The callbacks are still useful for main-thread mode.
   */
  setupTheatreIntegration() {
    if (!this.theatreSheet) return

    // Create Theatre.js controls for spline points
    const cameraPointControls = {};
    const targetPointControls = {};

    // Add controls for each camera spline point
    this.cameraPoints.forEach((point, index) => {
      cameraPointControls[`cam${index}_x`] = point.x;
      cameraPointControls[`cam${index}_y`] = point.y;
      cameraPointControls[`cam${index}_z`] = point.z;
    });

    // Add controls for each target spline point
    this.targetPoints.forEach((point, index) => {
      targetPointControls[`target${index}_x`] = point.x;
      targetPointControls[`target${index}_y`] = point.y;
      targetPointControls[`target${index}_z`] = point.z;
    });

    // Create a Theatre.js object for camera spline points
    this.cameraPointsObject = this.theatreSheet.object(
      `${this.sceneKey}_cameraPoints`,
      cameraPointControls
    );

    // Create a Theatre.js object for target spline points
    this.targetPointsObject = this.theatreSheet.object(
      `${this.sceneKey}_targetPoints`,
      targetPointControls
    );

    // Create a Theatre.js object for main camera controls
    this.theatreObject = this.mainTheatreSheet.object('Camera', {
      cameraProgress: distExports.types.number(0, { range: [0, 1], precision: 0.001 }),
      targetProgress: distExports.types.number(0, { range: [0, 1], precision: 0.001 }),
      debugMode: false,
      cameraRoll: distExports.types.number(0, {
        range: [-Math.PI, Math.PI],
        precision: 0.001
      }),
      cameraOffset: {
        x: distExports.types.number(0, { range: [-10, 10] }),
        y: distExports.types.number(0, { range: [-10, 10] }),
        z: distExports.types.number(0, { range: [-10, 10] })
      },
      targetOffset: {
        x: distExports.types.number(0, { range: [-50, 50] }),
        y: distExports.types.number(0, { range: [-50, 50] }),
        z: distExports.types.number(0, { range: [-50, 50] })
      }
    });

    // Listen to camera point changes
    this.cameraPointsObject.onValuesChange((values) => {
      this.cameraPoints.forEach((point, index) => {
        point.x = values[`cam${index}_x`];
        point.y = values[`cam${index}_y`];
        point.z = values[`cam${index}_z`];
      });
      this.updateCurves();
      this.updateSplineHelpers();

      // Update point helper positions
      this.pointHelpers.forEach((helper) => {
        if (helper.userData.type === 'camera') {
          const idx = helper.userData.index;
          helper.position.copy(this.cameraPoints[idx]);
        }
      });

      // Update camera if in non-debug mode
      if (!this.isDebugMode && this.theatreObject) {
        this.updateCameraFromProgress(
          this.theatreObject.value.cameraProgress,
          this.theatreObject.value.targetProgress
        );
      }
    });

    // Listen to target point changes
    this.targetPointsObject.onValuesChange((values) => {
      this.targetPoints.forEach((point, index) => {
        point.x = values[`target${index}_x`];
        point.y = values[`target${index}_y`];
        point.z = values[`target${index}_z`];
      });
      this.updateCurves();
      this.updateSplineHelpers();

      // Update point helper positions
      this.pointHelpers.forEach((helper) => {
        if (helper.userData.type === 'target') {
          const idx = helper.userData.index;
          helper.position.copy(this.targetPoints[idx]);
        }
      });

      // Update camera if in non-debug mode
      if (!this.isDebugMode && this.theatreObject) {
        this.updateCameraFromProgress(
          this.theatreObject.value.cameraProgress,
          this.theatreObject.value.targetProgress
        );
      }
    });

    // Listen to main camera control changes
    this.theatreObject.onValuesChange((values) => {
      this.updateCameraFromProgress(
        values.cameraProgress,
        values.targetProgress
      );

      if (values.debugMode !== this.isDebugMode) {
        this.toggleDebugMode(values.debugMode);
      }
    });
  }

  /**
   * Update camera position based on progress along spline (0-1)
   * @param {number} cameraProgress - Progress along camera spline (0-1)
   * @param {number} targetProgress - Progress along target spline (0-1)
   */
  updateCameraFromProgress(cameraProgress, targetProgress = cameraProgress) {
    const tCamera = Math.max(0, Math.min(1, cameraProgress));
    const tTarget = Math.max(0, Math.min(1, targetProgress));

    // Get position and target from curves using separate progress values
    const cameraPos = this.cameraCurve.getPoint(tCamera);
    const targetPos = this.targetCurve.getPoint(tTarget);

    // Apply offsets from Theatre.js controls
    if (this.theatreObject) {
      const values = this.theatreObject.value;
      if (values.cameraOffset) {
        cameraPos.x += values.cameraOffset.x;
        cameraPos.y += values.cameraOffset.y;
        cameraPos.z += values.cameraOffset.z;
      }
      if (values.targetOffset) {
        targetPos.x += values.targetOffset.x;
        targetPos.y += values.targetOffset.y;
        targetPos.z += values.targetOffset.z;
      }
    }

    // Store current target for visualization
    this.currentTarget.copy(targetPos);

    // Store current camera position for external access
    this.currentCameraPosition = cameraPos;

    // // Update camera (only if not in debug mode and no orbit controller)
    // if (!this.isDebugMode && !this.hasOrbitController) {
    //   this.camera.position.copy(cameraPos);
    //   this.camera.lookAt(targetPos);
    // }

    // Update target helper position (visible in both modes)
    if (this.targetHelper) {
      this.targetHelper.position.copy(targetPos);
    }

    // Update camera helper if in debug mode
    if (this.cameraHelper && this.isDebugMode) {
      this.cameraHelper.update();
    }
  }

  /**
   * Get current spline position and target for external use (e.g., orbit controller)
   */
  getCurrentSplineState() {
    if (!this.theatreObject) {
      return null
    }

    const values = this.theatreObject.value;
    const cameraProgress = values.cameraProgress;
    const targetProgress = values.targetProgress;
    const tCamera = Math.max(0, Math.min(1, cameraProgress));
    const tTarget = Math.max(0, Math.min(1, targetProgress));

    const position = this.cameraCurve.getPoint(tCamera);
    const target = this.targetCurve.getPoint(tTarget);

    // Apply offsets
    if (values.cameraOffset) {
      position.x += values.cameraOffset.x;
      position.y += values.cameraOffset.y;
      position.z += values.cameraOffset.z;
    }
    if (values.targetOffset) {
      target.x += values.targetOffset.x;
      target.y += values.targetOffset.y;
      target.z += values.targetOffset.z;
    }

    return {
      position,
      target,
      roll: values.cameraRoll || 0
    }
  }

  /**
   * Set whether an orbit controller is managing the camera
   */
  setHasOrbitController(hasController) {
    this.hasOrbitController = hasController;
  }

  /**
   * Toggle debug mode
   */
  toggleDebugMode(enabled) {
    this.isDebugMode = enabled;

    const debugView = getDebugView();

    if (enabled) {
      // Position debug camera to have a good view of the scene
      if (this.debugCamera) {
        // Position the debug camera to see both the splines and the camera
        const currentProgress = this.theatreObject?.value.targetProgress || 0;
        const targetOnCurve = this.targetCurve.getPoint(currentProgress);

        // Position debug camera at an offset from the target
        this.debugCamera.position.set(
          targetOnCurve.x + 20,
          targetOnCurve.y + 10,
          targetOnCurve.z + 20
        );
        this.debugCamera.lookAt(targetOnCurve);
      }

      // Show the debug view in the bottom-right corner
      if (debugView) {
        debugView.show(this.sceneKey);
      }

      // Disable the scene's orbit controller if it exists
      if (this.onDebugModeChanged) {
        this.onDebugModeChanged(true);
      }
    } else {
      // Hide the debug view
      if (debugView) {
        debugView.hide();
      }

      // Re-enable the scene's orbit controller if it exists
      if (this.onDebugModeChanged) {
        this.onDebugModeChanged(false);
      }
    }
  }

  /**
   * Note: Point selection is now handled through Theatre.js controls
   * instead of TransformControls due to webgpu compatibility
   */

  /**
   * Get current progress values
   */
  getProgress() {
    return {
      camera: this.theatreObject?.value.cameraProgress || 0,
      target: this.theatreObject?.value.targetProgress || 0
    }
  }

  /**
   * Set progress programmatically
   * @param {number} cameraProgress - Progress for camera position (0-1)
   * @param {number} targetProgress - Progress for target position (0-1), defaults to cameraProgress
   */
  setProgress(cameraProgress, targetProgress = cameraProgress) {
    this.updateCameraFromProgress(cameraProgress, targetProgress);
  }

  /**
   * Export spline data
   */
  exportData() {
    return {
      cameraPoints: this.cameraPoints.map((p) => ({ x: p.x, y: p.y, z: p.z })),
      targetPoints: this.targetPoints.map((p) => ({ x: p.x, y: p.y, z: p.z }))
    }
  }

  /**
   * Import spline data
   */
  importData(data) {
    if (data.cameraPoints) {
      this.cameraPoints = data.cameraPoints.map(
        (p) => new Vector3(p.x, p.y, p.z)
      );
    }
    if (data.targetPoints) {
      this.targetPoints = data.targetPoints.map(
        (p) => new Vector3(p.x, p.y, p.z)
      );
    }

    this.updateCurves();
    this.updateSplineHelpers();
  }

  /**
   * Get the currently active camera (debug or scene camera)
   */
  getActiveCamera() {
    return this.isDebugMode ? this.debugCamera : this.camera
  }

  /**
   * Update on animation frame
   */
  onRaf({ time, delta }) {
    // WORKAROUND: onValuesChange doesn't fire in web workers (offscreen mode)
    // So we need to manually read Theatre.js values and update camera each frame
    if (this.theatreObject) {
      const values = this.theatreObject.value;
      this.updateCameraFromProgress(
        values.cameraProgress,
        values.targetProgress
      );

      if (values.debugMode !== this.isDebugMode) {
        this.toggleDebugMode(values.debugMode);
      }
    }

    // Also manually update spline points from Theatre.js (workaround for web workers)
    if (this.cameraPointsObject) {
      const camValues = this.cameraPointsObject.value;
      let pointsChanged = false;

      this.cameraPoints.forEach((point, index) => {
        const newX = camValues[`cam${index}_x`];
        const newY = camValues[`cam${index}_y`];
        const newZ = camValues[`cam${index}_z`];

        if (point.x !== newX || point.y !== newY || point.z !== newZ) {
          point.x = newX;
          point.y = newY;
          point.z = newZ;
          pointsChanged = true;
        }
      });

      // Update point helper positions in debug mode
      if (pointsChanged && this.pointHelpers.length > 0) {
        this.pointHelpers.forEach((helper) => {
          if (helper.userData.type === 'camera') {
            const idx = helper.userData.index;
            helper.position.copy(this.cameraPoints[idx]);
          }
        });
      }
    }

    if (this.targetPointsObject) {
      const targetValues = this.targetPointsObject.value;
      let pointsChanged = false;

      this.targetPoints.forEach((point, index) => {
        const newX = targetValues[`target${index}_x`];
        const newY = targetValues[`target${index}_y`];
        const newZ = targetValues[`target${index}_z`];

        if (point.x !== newX || point.y !== newY || point.z !== newZ) {
          point.x = newX;
          point.y = newY;
          point.z = newZ;
          pointsChanged = true;
        }
      });

      // Update point helper positions in debug mode
      if (pointsChanged && this.pointHelpers.length > 0) {
        this.pointHelpers.forEach((helper) => {
          if (helper.userData.type === 'target') {
            const idx = helper.userData.index;
            helper.position.copy(this.targetPoints[idx]);
          }
        });
      }
    }

    // Update curves and helpers if points changed
    if (this.cameraPointsObject || this.targetPointsObject) {
      this.updateCurves();
      this.updateSplineHelpers();
    }

    // Update camera helper if in debug mode (shows where scene camera is)
    if (this.cameraHelper && this.isDebugMode) {
      this.cameraHelper.update();
    }
  }

  /**
   * Clean up resources
   */
  dispose() {
    // Remove helpers
    if (this.cameraSplineHelper) {
      this.scene.remove(this.cameraSplineHelper);
      this.cameraSplineHelper.geometry.dispose();
      this.cameraSplineHelper.material.dispose();
    }

    if (this.targetSplineHelper) {
      this.scene.remove(this.targetSplineHelper);
      this.targetSplineHelper.geometry.dispose();
      this.targetSplineHelper.material.dispose();
    }

    this.pointHelpers.forEach((helper) => {
      this.scene.remove(helper);
      helper.geometry.dispose();
      helper.material.dispose();
    });

    if (this.targetHelper) {
      this.scene.remove(this.targetHelper);
      this.targetHelper.geometry.dispose();
      this.targetHelper.material.dispose();
    }

    if (this.cameraHelper) {
      this.scene.remove(this.cameraHelper);
      this.cameraHelper.dispose();
    }

    if (this.transformControls) {
      this.transformControls.detach();
      this.scene.remove(this.transformControls.getHelper());
      this.transformControls.dispose();
    }

    // Unregister from debug view
    const debugView = getDebugView();
    if (debugView) {
      debugView.unregisterScene(this.sceneKey);
    }
  }
}

/**
 * Base class for section scene components
 * Handles common initialization, disposal, and HMR boilerplate
 * Now includes camera spline system with Theatre.js integration
 */
class SceneComponent extends component(null, {
  raf: {
    renderPriority: 1,
    fps: Number.Infinity
  }
}) {
  constructor(sceneKey) {
    super(sceneKey);

    this._readyPromise = null;
    this._maxDpr = Infinity; // Default: no DPR limit
    this._debugScaleFactor = 1.0; // Default: no debug scale adjustment
    this._shouldRender = true; // Ping-pong rendering control
  }

  async init(sceneKey) {
    this._readyPromise = (async () => {
      this.sceneKey = sceneKey;

      if (!store.multiScene) {
        console.error('MultiSceneCompositor not yet initialized');
        return
      }

      this.scene = store.multiScene.getScene(this.sceneKey);
      this.camera = store.multiScene.getCamera(this.sceneKey);

      // Get Theatre.js sheet for this scene
      this.theatreSheet = getSceneSheet(this.sceneKey);
      this.mainTheatreSheet = getSceneSheet('Main');

      // Create the scene content first
      await this.createScene();

      // Initialize camera spline system after scene is created
      await this.initCameraSplineSystem();

      this.afterSceneSetup();
    })();

    return this._readyPromise
  }

  afterSceneSetup() {
    // Hook for subclasses to run code after scene and camera are set up
  }

  /**
   * Returns a promise that resolves when the scene is fully initialized
   */
  ready() {
    return this._readyPromise || Promise.resolve()
  }

  /**
   * Set maximum device pixel ratio for this scene
   * Lower values can improve performance for complex scenes
   * @param {number} maxDpr - Maximum DPR (e.g., 1.5, 2.0)
   */
  setMaxDpr(maxDpr) {
    this._maxDpr = maxDpr;
    if (store.multiScene && this.sceneKey) {
      store.multiScene.updateSceneConfig(this.sceneKey, { maxDpr });
    }
  }

  /**
   * Get the current maximum DPR for this scene
   * @returns {number} The maximum DPR
   */
  getMaxDpr() {
    return this._maxDpr
  }

  /**
   * Set debug scale factor for camera spline debug helpers
   * Higher values make the debug spheres and helpers larger for better visibility
   * @param {number} scaleFactor - Scale multiplier (e.g., 1.0, 5.0, 10.0)
   */
  setDebugScaleFactor(scaleFactor) {
    this._debugScaleFactor = scaleFactor;
  }

  /**
   * Get the current debug scale factor
   * @returns {number} The debug scale factor
   */
  getDebugScaleFactor() {
    return this._debugScaleFactor
  }

  /**
   * Set whether this scene should update on the current frame
   * Part of the ping-pong rendering optimization
   * @param {boolean} shouldRender - Whether to update this frame
   */
  setShouldRender(shouldRender) {
    // this._shouldRender = shouldRender
    this.scene._shouldRender = shouldRender;
  }

  /**
   * Check if this scene should render on the current frame
   * @returns {boolean} True if should render
   */
  getShouldRender() {
    return this._shouldRender
  }

  setOrbitController() {
    if (this.camera && store.gl) {
      // In worker mode (offscreen), store.gl.domElement is an OffscreenCanvas which doesn't
      // have all the DOM methods (like getRootNode). Use virtualElement instead.
      // In main thread mode, use the actual canvas domElement.
      const isOffscreen = typeof window === 'undefined';
      const domElement = isOffscreen ? virtualElement : store.gl.domElement;

      this.cameraOrbit = new CameraOrbitController({
        camera: this.camera,
        renderer: {
          domElement: domElement
        }
      });

      // Set the orbit target to match where the imported camera was looking
      if (this.importedCameraTarget) {
        this.cameraOrbit.controls.target.copy(this.importedCameraTarget);
        this.cameraOrbit.target.copy(this.importedCameraTarget);
      }

      // Disable orbit controls when transform controls are active
      if (this.cameraSplineSystem) {
        this.cameraSplineSystem.onTransformDragging = (enabled) => {
          this.cameraOrbit.controls.enabled = enabled;
        };
        // Tell the spline system that orbit controller is active
        this.cameraSplineSystem.setHasOrbitController(true);
      }

      // Setup Theatre.js control for cameraMix (always, not just in debug mode)
      this.setupCameraMixControl();
    }
  }

  /**
   * Setup Theatre.js control for cameraMix
   * This is called regardless of debug mode since Theatre.js is always initialized
   * Uses the main sheet so cameraMix is grouped with other main camera controls
   * Note: onValuesChange callbacks don't fire in web workers (offscreen mode),
   * so we also manually read values in onRaf() as a workaround.
   */
  setupCameraMixControl() {
    if (!this.mainTheatreSheet || !this.cameraOrbit) return

    // Create Theatre.js object for camera mix control on the main sheet
    // This groups it with the other camera controls (cameraProgress, targetProgress, etc.)
    this.cameraControlObject = this.mainTheatreSheet.object(
      'Camera Controls',

      {
        cameraMix: distExports.types.number(this.cameraOrbit.controls.cameraMix, {
          range: [0, 1],
          precision: 0.01
        })
      },
      { reconfigure: true }
    );

    // Subscribe to changes and update camera controls
    this.cameraControlObject.onValuesChange((values) => {
      if (this.cameraOrbit && this.cameraOrbit.mixActive) {
        this.cameraOrbit.controls.cameraMix = values.cameraMix;
      }
    });
  }

  /**
   * Initialize camera spline system with Theatre.js integration
   */
  async initCameraSplineSystem() {
    if (!this.camera || !this.scene || !store.gl || !store.multiScene) {
      console.warn(
        'Cannot initialize camera spline system - missing dependencies'
      );
      return
    }

    this.cameraSplineSystem = new CameraSplineSystem({
      scene: this.scene,
      camera: this.camera,
      renderer: store.gl,
      sceneKey: this.sceneKey,
      theatreSheet: this.theatreSheet,
      mainTheatreSheet: this.theatreSheet,
      multiSceneCompositor: store.multiScene,
      debugScaleFactor: this._debugScaleFactor
    });

    // Hook up debug mode callback to handle orbit controls
    this.cameraSplineSystem.onDebugModeChanged = (debugEnabled) => {
      if (this.cameraOrbit) {
        // Disable scene orbit controls when in debug mode
        this.cameraOrbit.controls.enabled = !debugEnabled;
      }
    };
  }

  /**
   * Get the currently active camera for this scene (debug or main)
   */
  getActiveCamera() {
    if (this.cameraSplineSystem) {
      return this.cameraSplineSystem.getActiveCamera()
    }
    return this.camera
  }

  /**
   * Setup Theatre.js controls for camera (debug mode hook)
   * Note: cameraMix is now set up in setupCameraMixControl() regardless of debug mode
   */
  onDebug() {
    // Camera controls are now set up in setupCameraMixControl()
    // This hook is kept for potential future debug-only controls
  }

  /**
   * Override this method in subclasses to create scene content
   */
  createScene() {
    // Implemented by subclasses
  }

  onRaf30({ time, delta }) {
    // Ping-pong optimization: skip updates when not rendering
    if (!this._shouldRender) {
      return
    }

    // This method is throttled to 30fps using Tempus, so put any logic here that doesn't need to run every frame
  }

  /**
   * Override this method in subclasses for custom animations
   */
  onRaf({ time, delta }) {
    // Ping-pong optimization: skip updates when not rendering
    if (!this._shouldRender) {
      return
    }

    // WORKAROUND: onValuesChange doesn't fire in web workers (offscreen mode)
    // Manually read cameraMix value from Theatre.js each frame
    if (
      this.cameraControlObject &&
      this.cameraOrbit &&
      this.cameraOrbit.mixActive
    ) {
      const values = this.cameraControlObject.value;
      this.cameraOrbit.controls.cameraMix = values.cameraMix;
    }

    // Get spline state and feed it to orbit controller
    if (this.cameraSplineSystem && this.cameraOrbit) {
      const splineState = this.cameraSplineSystem.getCurrentSplineState();
      if (splineState) {
        this.cameraOrbit.updateFromSpline(
          splineState.position,
          splineState.target,
          splineState.roll
        );
      }
    }

    // Update camera orbit controller
    if (this.cameraOrbit) {
      this.cameraOrbit.onRaf({ time, delta });
    }

    // Update camera spline system
    if (this.cameraSplineSystem) {
      this.cameraSplineSystem.onRaf({ time, delta });
    }
  }

  dispose() {
    // Dispose camera spline system
    if (this.cameraSplineSystem) {
      this.cameraSplineSystem.dispose();
      this.cameraSplineSystem = null;
    }

    // Dispose orbit controller
    if (this.cameraOrbit) {
      this.cameraOrbit.dispose();
      this.cameraOrbit = null;
    }

    // Unregister from dispatcher
    this.destroy?.();

    // Clean up scene content for HMR
    if (this.scene) {
      const children = [...this.scene.children];
      children.forEach((child) => {
        disposeObject(child);
      });
      this.scene.clear();
    }

    // // Destroy debug folder if exists
    // if (this.folder) {
    //   this.folder.destroy();
    // }
  }
}

function getCascadeConfigsArray(cascades) {
  return [cascades.waves, cascades.ripples];
}

class WaveUniforms {
  animationSpeed = 1;
  amplitude = uniform(1);
  windSpeed = uniform(50);
  windDirection = uniform(0);
  choppiness = uniform(1);
  gravity = uniform(9.81);
  jonswapGamma = uniform(3.3);
  directionalSpreading = uniform(20);
  /** Set when any uniform changes. Consumers clear after reinit. */
  dirty = true;
  update(params) {
    this.animationSpeed = params.animationSpeed ?? this.animationSpeed;
    this.amplitude.value = params.amplitude;
    this.windSpeed.value = params.windSpeed;
    this.windDirection.value = params.windDirection;
    this.choppiness.value = params.choppiness;
    this.gravity.value = params.gravity ?? 9.81;
    this.jonswapGamma.value = params.jonswapGamma ?? 3.3;
    this.directionalSpreading.value = params.directionalSpreading;
    this.dirty = true;
  }
}
class SunUniforms {
  direction = uniform(new Vector3(0.5, 0.2, 0.5).normalize());
  intensity = uniform(1.5);
  update(params) {
    const elevation = MathUtils.degToRad(params.elevation);
    const azimuth = MathUtils.degToRad(params.azimuth);
    this.direction.value.set(
      Math.cos(elevation) * Math.sin(azimuth),
      Math.sin(elevation),
      Math.cos(elevation) * Math.cos(azimuth)
    ).normalize();
    this.intensity.value = params.intensity;
  }
}
