function createDefaultFoamTexture() {
  return new DataTexture(
    new Uint8Array([255, 255, 255, 255]),
    1,
    1,
    RGBAFormat,
    UnsignedByteType
  );
}

const sampleWakeBuffer = /* @__PURE__ */ Fn(
  ({
    worldX,
    worldZ,
    buffer,
    resolution,
    worldSize,
    originX,
    originZ
  }) => {
    const texelSize = worldSize.div(resolution);
    const halfRes = resolution.mul(0.5);
    const px = worldX.sub(originX).div(texelSize).add(halfRes);
    const py = worldZ.sub(originZ).div(texelSize).add(halfRes);
    const edgeMargin = resolution.mul(0.05);
    const fadeX = smoothstep(float(0), edgeMargin, px).mul(
      float(1).sub(smoothstep(resolution.sub(edgeMargin), resolution, px))
    );
    const fadeY = smoothstep(float(0), edgeMargin, py).mul(
      float(1).sub(smoothstep(resolution.sub(edgeMargin), resolution, py))
    );
    const edgeFade = fadeX.mul(fadeY);
    const x0Float = floor(px);
    const y0Float = floor(py);
    const fx = px.sub(x0Float);
    const fy = py.sub(y0Float);
    const res = int(resolution);
    const resMinusOne = res.sub(1);
    const x0 = clamp(x0Float.toInt(), int(0), resMinusOne);
    const y0 = clamp(y0Float.toInt(), int(0), resMinusOne);
    const x1 = clamp(x0.add(1), int(0), resMinusOne);
    const y1 = clamp(y0.add(1), int(0), resMinusOne);
    const d00 = buffer.element(y0.mul(res).add(x0));
    const d10 = buffer.element(y0.mul(res).add(x1));
    const d01 = buffer.element(y1.mul(res).add(x0));
    const d11 = buffer.element(y1.mul(res).add(x1));
    const d0 = mix(d00, d10, fx);
    const d1 = mix(d01, d11, fx);
    return mix(d0, d1, fy).mul(edgeFade);
  }
);

