      foamResult.combinedFoamColor.x.mul(float(0.3).add(NdotL.mul(0.7))),
      foamResult.combinedFoamColor.y.mul(float(0.3).add(NdotL.mul(0.7))),
      foamResult.combinedFoamColor.z.mul(float(0.3).add(NdotL.mul(0.7)))
