  // All injected from WaterSystem via SharedMaterialUniforms.
  // WaterSystem owns these — they survive quality level changes.
  waterColor;
  fresnel;
  debug;
  surfaceFoam;
  waveFoam;
  shorelineFoam;
  sss;
  sparkle;
  ssr;
  underwaterSurfaceGlow;
  // ============= Infrastructure =============
  /** CascadeSampler for WebGPU cascade buffer sampling. Null for WebGL. */
  cascadeSampler = null;
  maskEnabledUniform;
