      waterColor: this.waterColor,
      fresnel: this.fresnel,
      debug: this.debug,
      surfaceFoam: this.features.surfaceFoam ? this.surfaceFoam : null,
      waveFoam: this.features.turbulentFoam ? this.waveFoam : null,
      shorelineFoam: this.features.shorelineFoam ? this.shorelineFoam : null,
      sparkle: this.features.sparkle ? this.sparkle : null,
      ssr: this.features.ssr ? this.ssr : null,
      sss: this.features.sss ? this.sss : null,
      underwaterSurfaceGlow: this.features.underwaterTIR ? this.underwaterSurfaceGlow : null,
      skyProvider: this.skyProvider,
      environmentMap: this.environmentMap,
      features: this.features,
