/**
 * WaterPro component - Basic water surface with reflections
 * Includes ocean simulation, visible water surface, and object reflections
 */
class WaterPro {
  constructor(params = {}) {
    this.params = {
      renderer: params.renderer,
      scene: params.scene,
      camera: params.camera,
      quality: params.quality ?? 'low',
      preset: params.preset ?? 'storm',
      includeSky: params.includeSky ?? true
    };

    this.isUpdated = false;

    this.oceanSim = null;
    this.waterMaterial = null;
    this.clipmap = null;
    this.renderPassManager = null;
    this.sky = null;
    this.time = 0;

    // Uniform instances
    this.waveUniforms = null;
    this.sunUniforms = null;
    this.waveFoam = null;
    this.gerstner = null;

    // Shader instances (all required by WaterSurfaceMaterial)
    this.debug = null;
    this.waterColor = null;
    this.fresnel = null;
    this.shorelineFoam = null;
    this.ssr = null;
    this.sss = null;
    this.sparkle = null;
    this.surfaceFoam = null;
    this.underwaterSurfaceGlow = null;
    this.waterline = null;
  }

  /**
   * Async initialization - creates basic water with reflections
   */
  async create() {
    const preset = getPresetParams(this.params.preset);
    const qualityConfig = QUALITY_LEVELS[this.params.quality];

    // Create uniform instances
    this.waveUniforms = new WaveUniforms();
    this.waveUniforms.update(preset.waves.fft);

    this.sunUniforms = new SunUniforms();
    this.sunUniforms.update(preset.sky.sun);

    this.waveFoam = new WaveFoam();
    this.waveFoam.update(preset.foam.waves);

    // Create shader instances for material (all required by WaterSurfaceMaterial)
    this.debug = new Debug();

    this.waterColor = new WaterColor();
    this.waterColor.update(preset.color);

    this.fresnel = new Fresnel();
    this.fresnel.update(preset.fresnel.surface);

    // this.shorelineFoam = new ShorelineFoam();
    // this.shorelineFoam.update(preset.foam.shoreline);

    this.ssr = new SSR();
    this.ssr.update(preset.ssr);

    // this.sss = new SSS();
    // this.sss.update(preset.sss);

    // this.sparkle = new Sparkle();
    // this.sparkle.update(preset.sparkle);

    // this.surfaceFoam = new SurfaceFoam();
    // this.surfaceFoam.update(preset.foam.surface);

    // this.underwaterSurfaceGlow = new UnderwaterSurfaceGlow();
    // this.underwaterSurfaceGlow.update(preset.oceanFloor.surfaceGlow);

    this.waterline = new Waterline();

    // Create ocean simulation
    this.oceanSim = createWaveSimulation(this.params.renderer, {
      qualityConfig,
      cascades: preset.waves.fft.cascades,
      waveUniforms: this.waveUniforms,
      foamWindBias: this.waveFoam._windBiasNode
    });

    this.oceanSim.init();
    await this.oceanSim.initializeBuffers(this.params.renderer);

    // Create Gerstner waves
    this.gerstner = new Gerstner(this.waveUniforms, () => {
      this.oceanSim.updateGerstnerParams(this.gerstner.getInternalParams());
    });

    this.gerstner.update(preset.waves.gerstner);

    // Create water material with all required shader uniforms
    const sharedUniforms = {
      maskEnabled: uniform(0.0), // No masking in basic water setup
      sunDirection: this.sunUniforms.direction,
      sunIntensity: this.sunUniforms.intensity,
      windDirection: this.waveUniforms.windDirection,
      debug: this.debug,
      fresnel: this.fresnel,
      // shorelineFoam: this.shorelineFoam,
      // sparkle: this.sparkle,
      ssr: this.ssr,
      // sss: this.sss,
      // surfaceFoam: this.surfaceFoam,
      // underwaterSurfaceGlow: this.underwaterSurfaceGlow,
      waterColor: this.waterColor,
      waterline: this.waterline,
      waveFoam: this.waveFoam
    };

    this.waterMaterial = new WaterSurfaceMaterial(
      this.oceanSim,
      sharedUniforms,
      undefined,
      this.params.quality
    );
    this.waterMaterial.ssr.maxDistance = qualityConfig.ssrMaxDistance;
    this.waterMaterial.ssr.stepCount = qualityConfig.ssrStepCount;

    // Create water geometry (clipmap)
    this.clipmap = new WaterSurfaceGeometry(
      {
        levels: preset.clipmap.levels,
        segments: qualityConfig.segments,
        baseSize: preset.clipmap.baseSize
      },
      this.waterMaterial
    );
    this.params.scene.add(this.clipmap.getObject());

    // Create render pass manager (needed for SSR scene color pass)
    this.renderPassManager = new RenderPassManager(
      this.params.renderer,
      this.params.scene,
      this.params.camera,
      this.clipmap,
      this.waterMaterial,
      null,
      null,
      null,
      null,
      []
    );

    // Enable scene color texture usage for SSR
    this.waterMaterial.useSceneColorTextureUniform.value = 1.0;

    // Add sky if requested
    if (this.params.includeSky) {
      this.sky = new RayleighSky(preset.sky);
      this.params.scene.add(this.sky.getMesh());
      this.waterMaterial.setSky(this.sky);
      this.renderPassManager.setSky(this.sky);
    }

    // Apply preset parameters (critical for correct appearance)
    this.applyPresetParams(preset);

    // Sync fade distances to water extent
    this.syncFadeEndToWaterExtent();

    // Initial update
    this.params.camera.updateMatrixWorld(true);
    this.oceanSim.update(0);
    this.clipmap.update(this.params.camera.position);
    this.renderPassManager.renderDepthPass(this.params.renderer);

    setTimeout(() => {
      this.isUpdated = true;
    }, 1000);

    return this
  }

  /**
   * Apply all preset parameters to configure the water appearance
   */
  applyPresetParams(preset) {
    // Set water depth for color calculations
    this.waterColor.waterDepth = preset.oceanFloor.depth;

    // Update cascade configurations with frequency and amplitude modifiers
    this.updateAllCascadeConfigs(preset);
  }

  /**
   * Update all cascade configurations from preset
   */
  updateAllCascadeConfigs(preset) {
    const configs = getCascadeConfigsArray(preset.waves.fft.cascades);
    for (let i = 0; i < configs.length; i++) {
      const config = configs[i];
      this.oceanSim.updateCascadeConfig(i, {
        ...config,
        scale: config.scale / preset.waves.fft.frequency,
        amplitudeScale: config.amplitudeScale * preset.waves.fft.amplitude
      });
    }

    // Update material cascade uniforms
    this.waterMaterial.updateCascadeUniforms();
  }

  /**
   * Sync fade distances to match water extent
   */
  syncFadeEndToWaterExtent() {
    const waterExtent = this.clipmap.getTotalSize() / 2;
    this.fresnel.fadeEnd = waterExtent;
  }

  /**
   * Static factory method for async creation
   */
  static async create(params) {
    const waterPro = new WaterPro(params);
    await waterPro.create();
    return waterPro
  }

  /**
   * Get the ocean simulation instance
   */
  getOceanSim() {
    return this.oceanSim
  }

  /**
   * Get the sky instance if created
   */
  getSky() {
    return this.sky
  }

  /**
   * Get the sky fog uniforms for studio control.
   * Exposes fogColor, gradientStart, gradientEnd, gradientPower.
   */
  getSkyFogUniforms() {
    return this.sky?.skyFogUniforms ?? null
  }

  /**
   * Get the water mesh object
   */
  getWaterMesh() {
    return this.clipmap?.getObject()
  }

  /**
   * Get wave uniforms for control
   */
  getWaveUniforms() {
    return this.waveUniforms
  }

  /**
   * Set water position
   */
  setPosition(x, y, z) {
    const waterMesh = this.getWaterMesh();
    if (waterMesh) {
      waterMesh.position.set(x, y, z);
    }
  }

  /**
   * Set water scale
   */
  setScale(x, y, z) {
    const waterMesh = this.getWaterMesh();
    if (waterMesh) {
      waterMesh.scale.set(x, y, z);
    }
  }

  /**
   * Update water - call this in your render loop BEFORE rendering
   */
  async update(delta) {
    this.time += delta;
    this.waterMaterial.timeUniform.value = this.time;

    // Sync animation speed
    this.oceanSim.animationSpeed = this.waveUniforms.animationSpeed;

    // Update Gerstner waves if wave uniforms changed
    if (this.waveUniforms.dirty) {
      this.gerstner.triggerUpdate();
    }

    // Update camera forward for material

    if (!this.isUpdated) {
      // Update clipmap position
      this.clipmap.update(this.params.camera.position);
      const snappedPos = this.clipmap.getSnappedPosition();
      this.waterMaterial.clipmapOffsetUniform.value.set(
        snappedPos.x,
        snappedPos.y
      );
      const cameraForward = this.params.camera.getWorldDirection(
        new Vector3()
      );
      this.waterMaterial.updateCameraForward(cameraForward);
    }
    // Update ocean simulation
    this.oceanSim.update(delta);

    // Render depth pass - needed for depth-based effects
    // this.params.renderer.info.reset();
    this.renderPassManager.renderDepthPass(this.params.renderer);

    // Render scene color pass for SSR if enabled
    if (this.ssr.enabled) {
      this.renderPassManager.renderSceneColorPass(this.params.renderer);
    }
  }

  /**
   * Set the scene color texture for SSR (screen-space reflections)
   * Call this to connect the post-processing scene pass to the water material
   *
   * @param {THREE.Texture} sceneTexture - Scene color texture from post-processing
   */
  setSceneColorTexture(sceneTexture) {
    if (this.waterMaterial) {
      this.waterMaterial.setSceneColorTexture(sceneTexture);
      this.waterMaterial.useSceneColorTextureUniform.value = 1.0;
    }
  }

  /**
   * Resize handler
   */
  resize() {
    this.renderPassManager?.resize();
  }

  /**
   * Load a different preset
   */
  loadPreset(presetName) {
    const preset = getPresetParams(presetName);

    if (this.waveUniforms) {
      this.waveUniforms.update(preset.waves.fft);
    }

    if (this.sunUniforms) {
      this.sunUniforms.update(preset.sky.sun);
    }

    if (this.waveFoam) {
      this.waveFoam.update(preset.foam.waves);
    }

    if (this.waterColor) {
      this.waterColor.update(preset.color);
    }

    if (this.fresnel) {
      this.fresnel.update(preset.fresnel.surface);
    }

    if (this.ssr) {
      this.ssr.update(preset.ssr);
    }

    if (this.sparkle) {
      this.sparkle.update(preset.sparkle);
    }

    if (this.gerstner) {
      this.gerstner.update(preset.waves.gerstner);
    }

    if (this.sky) {
      // Update sky with new preset
      this.sky.dispose();
      this.params.scene.remove(this.sky.getMesh());
      this.sky = new RayleighSky(preset.sky);
      this.params.scene.add(this.sky.getMesh());
      this.waterMaterial.setSky(this.sky);
      this.renderPassManager.setSky(this.sky);
    }
  }

  /**
   * Dispose resources
   */
  dispose() {
    if (this.oceanSim) {
      this.oceanSim.dispose();
      this.oceanSim = null;
    }

    if (this.clipmap) {
      this.params.scene.remove(this.clipmap.getObject());
      this.clipmap.dispose();
      this.clipmap = null;
    }

    if (this.waterMaterial) {
      this.waterMaterial.dispose();
      this.waterMaterial = null;
    }

    if (this.renderPassManager) {
      this.renderPassManager.dispose();
      this.renderPassManager = null;
    }

    if (this.sky) {
      this.sky.dispose();
      this.params.scene.remove(this.sky.getMesh());
      this.sky = null;
    }
  }
}

/**
 * MainModel component - Handles the intro GLTF model
 * Includes model loading, material controls, and Theatre.js integration
 */
class MainModel {
  constructor(params = {}) {
    this.params = {
      scene: params.scene,
      camera: params.camera,
      theatreSheet: params.theatreSheet,
      envRenderTarget: params.envRenderTarget,
      mainSceneObject: params.mainSceneObject
    };

    this.model = null;
    this.materials = {};
    this.importedCameraTarget = null;

    // Theatre.js objects
    this.spireMaterialObject = null;
    this.mainModelTransformObject = null;
    this.floatingAnimationObject = null;

    // Texture adjustment uniforms
    this.spireTextureHue = null;
    this.spireTextureSaturation = null;
    this.spireTextureContrast = null;
    this.spireTextureVibrance = null;
    this.spireTextureLuminance = null;

    // Floating block animation
    this.spireBlocks = [];
    this.time = 0;
    this.mouseInfluenceFade = 0; // Current fade value for mouse influence (0-1)
    this.mouseInfluenceFadeTween = null; // GSAP tween for fade animation

    // Mouse interaction
    this.raycaster = new Raycaster();
    this.mouse = new Vector2();
    this.interactionPlane = null;
    this.mouseWorldPosition = new Vector3();
    this.isMouseOnPlane = false;
    this.mouseInteractionObject = null;
    this.interactionPlaneTransformObject = null;

    // Canvas size (will be updated from resize events)
    this.canvasWidth = store.canvasSize?.width || 1;
    this.canvasHeight = store.canvasSize?.height || 1;

    // Debug visualization
    this.debugSphere = null;
    this.debugInfluenceCircle = null;

    // Debug flag for mouse interaction
    this.debugMouseInteraction = true;

    // Track if mouse tracking is enabled
    this.isMouseTrackingEnabled = false;

    // Reveal mask uniforms (populated in setupRevealMask)
    this.maskRevealY = null;
    this.maskEdgeSoftness = null;
    this.maskNoiseScale = null;
    this.maskNoiseStrength = null;
    this.maskNoiseSpeed = null;
    this.maskEdgeGlowWidth = null;
    this.maskEdgeGlowIntensity = null;
    this.maskEdgeGlowColor = null;
    this.maskTime = null;
    this.revealMaskObject = null;

    // Bind mouse event handlers
    this.onMouseMove = this.handleMouseMove.bind(this);
    this.onResize = this.handleResize.bind(this);
    this.onSceneUiVisibilityChanged =
      this.handleSceneUiVisibilityChanged.bind(this);

    this.onSceneVisibilityChanged = this.handleSceneVisibilityChanged.bind(this);

    // Listen to scene visibility changes to auto-enable/disable mouse tracking
    dispatcherSingleton.on('sceneUIVisibilityChanged', this.onSceneUiVisibilityChanged);
    dispatcherSingleton.on('sceneVisibilityChanged', this.onSceneVisibilityChanged);
  }

  /**
   * Async initialization - loads and sets up the GLTF model
   */
  async create() {
    // Load GLTF model
    const introGltf = loader.resources.introModel?.asset;
    if (!introGltf) {
      return this
    }

    this.model = introGltf.scene;
    this.model.position.set(0, 0, 0);

    // Find and copy Camera001 settings
    let importedCamera = null;
    this.model.traverse((child) => {
      if (child.isCamera && child.name === 'Camera001') {
        importedCamera = child;
      }

      if (child.isMesh) {
        // child.castShadow = true
        // child.receiveShadow = true

        // Store reference to Spire Blocks / Material and meshes
        if (child.material) {
          const materialName = child.material.name;
          if (materialName === 'Spire.002') {
            this.materials[materialName] = child.material;

            // Store mesh reference with animation data
            this.spireBlocks.push({
              mesh: child,
              originalPosition: child.position.clone(),
              timeOffset: Math.random() * Math.PI * 2, // Random phase offset
              currentMouseDisplacement: new Vector3(0, 0, 0), // Smooth displacement from mouse
              smoothedPosition: child.position.clone() // Final smoothed position for extra smoothing
            });
          }
        }
      }
    });

    // Apply camera settings from imported Camera001
    if (importedCamera && this.params.camera) {
      this.params.camera.position.copy(importedCamera.position);
      this.params.camera.rotation.copy(importedCamera.rotation);
      this.params.camera.quaternion.copy(importedCamera.quaternion);

      if (importedCamera.isPerspectiveCamera) {
        this.params.camera.fov = importedCamera.fov;
        this.params.camera.near = 1;
        this.params.camera.far = importedCamera.far;
        this.params.camera.updateProjectionMatrix();
      }

      // Calculate where the camera is looking
      const direction = new Vector3();
      importedCamera.getWorldDirection(direction);
      const targetPoint = new Vector3(-0.3, 2.5, 0);

      // Store target for orbit controller
      this.importedCameraTarget = targetPoint;
    }

    // Add to scene
    this.params.scene.add(this.model);

    // Create invisible interaction plane
    this.createInteractionPlane();

    // Setup Theatre.js controls if available
    if (this.params.theatreSheet) {
      this.setupMaterialControls();
      this.setupTransformControls();
      this.setupFloatingAnimation();
      this.setupMouseInteraction();
      this.setupInteractionPlaneControls();
    }

    // Setup reveal mask (always, Theatre.js controls added conditionally inside)
    this.setupRevealMask();

    // Apply environment map if available
    if (this.params.envRenderTarget) {
      this.applyEnvironmentMap(this.params.envRenderTarget);
    }

    return this
  }

  /**
   * Setup Theatre.js controls for material properties
   */
  setupMaterialControls() {
    if (!this.params.theatreSheet) {
      return
    }

    // Helper function to convert hex color to RGBA object
    const hexToRgba = (hex) => {
      const color = new Color(hex);
      return { r: color.r, g: color.g, b: color.b, a: 1.0 }
    };

    // Setup controls for Spire Blocks / Material
    if (this.materials['Spire.002']) {
      const spireMaterial = this.materials['Spire.002'];

      // Create uniform nodes for texture adjustments
      this.spireTextureHue = uniform(0); // -1 to 1
      this.spireTextureSaturation = uniform(1); // 0 to 2
      this.spireTextureContrast = uniform(1); // 0 to 2
      this.spireTextureVibrance = uniform(0); // -1 to 1
      this.spireTextureLuminance = uniform(1); // 0 to 2

      // If the material has a base texture, apply adjustments
      if (spireMaterial.map) {
        const baseTexture = texture(spireMaterial.map);

        // Apply adjustments in sequence
        let adjustedColor = baseTexture.rgb;

        // Apply hue shift
        adjustedColor = hue(adjustedColor, this.spireTextureHue);

        // Apply saturation
        adjustedColor = saturation(adjustedColor, this.spireTextureSaturation);

        // Apply vibrance (affects less saturated colors more)
        adjustedColor = vibrance(adjustedColor, this.spireTextureVibrance);

        // Apply contrast: (color - 0.5) * contrast + 0.5
        adjustedColor = adjustedColor
          .sub(0.5)
          .mul(this.spireTextureContrast)
          .add(0.5);

        // Apply luminance/brightness
        adjustedColor = adjustedColor.mul(this.spireTextureLuminance);

        // Apply the adjusted texture to the material's colorNode
        spireMaterial.colorNode = adjustedColor;
      }

      this.spireMaterialObject = this.params.theatreSheet.object(
        'Spire Blocks / Material',
        {
          color: distExports.types.rgba(hexToRgba(spireMaterial.color.getHex())),
          emissive: distExports.types.rgba(
            hexToRgba(spireMaterial.emissive?.getHex() || 0x000000)
          ),
          roughness: distExports.types.number(spireMaterial.roughness, {
            range: [0, 1],
            precision: 0.01
          }),
          metalness: distExports.types.number(spireMaterial.metalness || 0, {
            range: [0, 1],
            precision: 0.01
          }),
          envMapIntensity: distExports.types.number(spireMaterial.envMapIntensity || 1.0, {
            range: [0, 3],
            precision: 0.01
          }),
          textureHue: distExports.types.number(0, {
            range: [-1, 1],
            precision: 0.01
          }),
          textureSaturation: distExports.types.number(1, {
            range: [0, 2],
            precision: 0.01
          }),
          textureVibrance: distExports.types.number(0, {
            range: [-1, 1],
            precision: 0.01
          }),
          textureContrast: distExports.types.number(1, {
            range: [0, 2],
            precision: 0.01
          }),
          textureLuminance: distExports.types.number(1, {
            range: [0, 2],
            precision: 0.01
          })
        }
      );

      this.spireMaterialObject.onValuesChange((values) => {
        spireMaterial.color
          .setRGB(values.color.r, values.color.g, values.color.b)
          .convertSRGBToLinear();
        if (spireMaterial.emissive) {
          spireMaterial.emissive
            .setRGB(values.emissive.r, values.emissive.g, values.emissive.b)
            .convertSRGBToLinear();
        }
        spireMaterial.roughness = values.roughness;
        spireMaterial.metalness = values.metalness;
        spireMaterial.envMapIntensity = values.envMapIntensity;

        // Update texture adjustment uniforms
        this.spireTextureHue.value = values.textureHue;
        this.spireTextureSaturation.value = values.textureSaturation;
        this.spireTextureVibrance.value = values.textureVibrance;
        this.spireTextureContrast.value = values.textureContrast;
        this.spireTextureLuminance.value = values.textureLuminance;
      });
    }
  }

  /**
   * Setup Theatre.js controls for model transform
   */
  setupTransformControls() {
    if (!this.params.theatreSheet || !this.model) {
      return
    }

    // Theatre.js controls for Main Model Transform
    this.mainModelTransformObject = this.params.theatreSheet.object(
      'Spire Blocks / Transform',
      {
        positionX: distExports.types.number(this.model.position.x, {
          range: [-600, 600],
          precision: 0.001
        }),
        positionY: distExports.types.number(this.model.position.y, {
          range: [-600, 600],
          precision: 0.001
        }),
        positionZ: distExports.types.number(this.model.position.z, {
          range: [-600, 600],
          precision: 0.001
        }),
        scaleX: distExports.types.number(this.model.scale.x, {
          range: [0.1, 100],
          precision: 0.001
        }),
        scaleY: distExports.types.number(this.model.scale.y, {
          range: [0.1, 100],
          precision: 0.001
        }),
        scaleZ: distExports.types.number(this.model.scale.z, {
          range: [0.1, 100],
          precision: 0.001
        })
      }
    );

    // Listen to transform changes
    this.mainModelTransformObject.onValuesChange((values) => {
      this.model.position.set(
        values.positionX,
        values.positionY,
        values.positionZ
      );
      this.model.scale.set(values.scaleX, values.scaleY, values.scaleZ);
    });
  }

  /**
   * Setup Theatre.js controls for floating block animation
   */
  setupFloatingAnimation() {
    if (!this.params.theatreSheet || this.spireBlocks.length === 0) {
      return
    }

    // Calculate default center point (average of all block positions)
    const centerPoint = new Vector3();
    this.spireBlocks.forEach((block) => {
      centerPoint.add(block.originalPosition);
    });
    centerPoint.divideScalar(this.spireBlocks.length);

    this.floatingAnimationObject = this.params.theatreSheet.object(
      'Spire Blocks / Floating Animation',
      {
        enabled: distExports.types.boolean(false),
        centerX: distExports.types.number(centerPoint.x, {
          range: [-50, 50],
          precision: 0.01
        }),
        centerY: distExports.types.number(centerPoint.y, {
          range: [-50, 50],
          precision: 0.01
        }),
        centerZ: distExports.types.number(centerPoint.z, {
          range: [-50, 50],
          precision: 0.01
        }),
        floatDistance: distExports.types.number(2.0, {
          range: [0, 0.5],
          precision: 0.001
        }),
        floatSpeed: distExports.types.number(1.0, {
          range: [0, 5],
          precision: 0.01
        }),
        noiseFrequency: distExports.types.number(1.0, {
          range: [0, 5],
          precision: 0.01
        }),
        noiseAmplitude: distExports.types.number(0.5, {
          range: [0, 10],
          precision: 0.01
        }),
        noiseSpeed: distExports.types.number(1.0, {
          range: [0, 5],
          precision: 0.01
        }),
        horizontalScale: distExports.types.number(1.5, {
          range: [0.1, 5],
          precision: 0.1
        }),
        verticalScale: distExports.types.number(1.0, {
          range: [0.1, 5],
          precision: 0.1
        }),
        cornerScale: distExports.types.number(0.7, {
          range: [0.1, 5],
          precision: 0.1
        }),
        positionSmoothing: distExports.types.number(0.05, {
          range: [0.01, 1],
          precision: 0.01
        }),
        maxTravelDistance: distExports.types.number(0.5, {
          range: [0.1, 1],
          precision: 0.01
        })
      }
    );
  }

  /**
   * Apply a bottom-to-top reveal mask with perlin-noise edge and edge glow
   * to every material on the model. Theatre.js controls added when sheet available.
   */
  setupRevealMask() {
    if (!this.model) return

    // Load perlin texture from common resources
    const perlinAsset = loader.resources.perlinTexture?.asset;
    if (perlinAsset) {
      perlinAsset.wrapS = RepeatWrapping;
      perlinAsset.wrapT = RepeatWrapping;
    }

    // TSL uniforms — defaults keep the model fully visible until animated
    this.maskRevealY = uniform(20.0); // World-Y of the reveal edge
    this.maskEdgeSoftness = uniform(0.5); // Fade band width (world units)
    this.maskNoiseScale = uniform(0.5); // Perlin UV scale
    this.maskNoiseStrength = uniform(0.5); // Edge displacement by noise
    this.maskNoiseSpeed = uniform(0.1); // Noise scroll speed
    this.maskEdgeGlowWidth = uniform(0.3); // Glow band width (world units)
    this.maskEdgeGlowIntensity = uniform(3.0); // Glow brightness multiplier
    this.maskEdgeGlowColor = uniform(new Color(0.3, 0.8, 1.0)); // Cool-blue glow
    this.maskTime = uniform(0.0); // Updated each frame for noise animation

    const perlinNode = perlinAsset ? texture(perlinAsset) : null;

    const processedMaterials = new Set();

    this.model.traverse((child) => {
      if (!child.isMesh || !child.material) return
      if (processedMaterials.has(child.material)) return
      processedMaterials.add(child.material);

      const mat = child.material;
      mat.transparent = true;
      mat.alphaTest = 0.5;
      // mat.depthWrite = false // Prevents the Spire from ever "cutting" into the water's depth
      // mat.depthTest = true

      // World-space XZ → perlin UV, scrolled over time
      const noiseUV = positionWorld.xz
        .mul(this.maskNoiseScale)
        .add(vec2(0.0, this.maskTime.mul(this.maskNoiseSpeed)));

      // Noise offset centres around 0 (-0.5 … +0.5 × strength)
      const noiseOffset = perlinNode
        ? perlinNode.sample(noiseUV).r.sub(0.5).mul(this.maskNoiseStrength)
        : float(0.0);

      // World Y perturbed by noise
      const effectiveY = positionWorld.y.add(noiseOffset);

      // Mask: 1 (visible) below the edge, 0 (hidden) above it
      // smoothstep(high, low, x) is 1 when x ≤ low, 0 when x ≥ high
      const mask = smoothstep(
        this.maskRevealY,
        this.maskRevealY.sub(this.maskEdgeSoftness),
        effectiveY
      );

      // Edge glow: peaks exactly at the reveal edge, falls off within glowWidth
      const distToEdge = effectiveY.sub(this.maskRevealY).abs();
      const edgeGlow = smoothstep(
        this.maskEdgeGlowWidth,
        float(0.0),
        distToEdge
      );

      // Calculate the distance from the current pixel's world Y to your reveal Y
      // Anything with a negative distance is clipped (discarded)

      // Apply clipping: pixels where dist > 0 will be removed
      // If your reveal is bottom-up, use: this.maskRevealY.sub(positionWorld.y)
      mat.clippingNode = float(0);

      mat.maskNode = mask;

      const glowContribution = this.maskEdgeGlowColor
        .mul(edgeGlow)
        .mul(this.maskEdgeGlowIntensity);

      mat.emissiveNode = materialEmissive.add(glowContribution);

      mat.needsUpdate = true;
    });

    if (this.params.theatreSheet) {
      this.setupRevealMaskControls();
    }
  }

  /**
   * Theatre.js sheet controls for the reveal mask
   */
  setupRevealMaskControls() {
    const hexToRgba = (hex) => {
      const c = new Color(hex);
      return { r: c.r, g: c.g, b: c.b, a: 1.0 }
    };

    this.revealMaskObject = this.params.theatreSheet.object(
      'Spire Blocks / Reveal Mask',
      {
        revealY: distExports.types.number(20.0, {
          range: [-150, 250],
          precision: 0.01
        }),
        edgeSoftness: distExports.types.number(0.5, {
          range: [0, 3],
          precision: 0.01
        }),
        noiseScale: distExports.types.number(0.03, {
          range: [0, 0.03],
          precision: 0.001
        }),
        noiseStrength: distExports.types.number(0.5, {
          range: [0, 50],
          precision: 0.01
        }),
        noiseSpeed: distExports.types.number(0.1, {
          range: [0, 2],
          precision: 0.01
        }),
        edgeGlowWidth: distExports.types.number(0.3, {
          range: [0, 10],
          precision: 0.01
        }),
        edgeGlowIntensity: distExports.types.number(3.0, {
          range: [0, 20],
          precision: 0.01
        }),
        edgeGlowColor: distExports.types.rgba(
          hexToRgba(new Color(0.3, 0.8, 1.0).getHex())
        )
      }
    );

    this.revealMaskObject.onValuesChange((values) => {
      this.maskRevealY.value = values.revealY;
      this.maskEdgeSoftness.value = values.edgeSoftness;
      this.maskNoiseScale.value = values.noiseScale;
      this.maskNoiseStrength.value = values.noiseStrength;
      this.maskNoiseSpeed.value = values.noiseSpeed;
      this.maskEdgeGlowWidth.value = values.edgeGlowWidth;
      this.maskEdgeGlowIntensity.value = values.edgeGlowIntensity;
      this.maskEdgeGlowColor.value.setRGB(
        values.edgeGlowColor.r,
        values.edgeGlowColor.g,
        values.edgeGlowColor.b
      );
    });
  }

  /**
   * Create an invisible plane for mouse interaction
   */
  createInteractionPlane() {
    // Create a large plane geometry centered on the model
    const geometry = new PlaneGeometry(2, 2);
    const material = new MeshBasicMaterial({
      color: 0x00ff00, // Green for visibility
      transparent: true,
      opacity: 0, // Semi-transparent
      side: DoubleSide,
      wireframe: false,
      depthTest: false,
      depthWrite: false
    });

    this.interactionPlane = new Mesh(geometry, material);
    this.interactionPlane.visible = false; // Visible for debugging

    // Position the plane at the model's position
    this.interactionPlane.position.set(0, 2.75, -1);
    // this.interactionPlane.rotation.y = -0.5;

    // Make the plane face the camera (perpendicular to Z-axis by default)
    // We'll keep it in XY plane

    this.model.add(this.interactionPlane);

    // Create debug sphere to visualize mouse position
    const sphereGeometry = new SphereGeometry(10.5, 16, 16);
    const sphereMaterial = new MeshBasicMaterial({
      color: 0xff0000, // Red sphere
      transparent: true,
      opacity: 0,
      depthTest: false,
      depthWrite: false
    });

    this.debugSphere = new Mesh(sphereGeometry, sphereMaterial);
    this.debugSphere.visible = false; // Visible for debugging
    this.params.scene.add(this.debugSphere);
  }

  /**
   * Setup Theatre.js controls for mouse interaction
   */
  setupMouseInteraction() {
    if (!this.params.theatreSheet) {
      return
    }

    this.mouseInteractionObject = this.params.theatreSheet.object(
      'Spire Blocks / Mouse Interaction',
      {
        enabled: distExports.types.boolean(true), // Enabled by default for debugging
        influenceRadius: distExports.types.number(10.0, {
          range: [0, 50],
          precision: 0.1
        }),
        pushStrength: distExports.types.number(5.0, {
          range: [0, 20],
          precision: 0.1
        }),
        falloffPower: distExports.types.number(2.0, {
          range: [0.5, 4],
          precision: 0.1
        }),
        smoothing: distExports.types.number(0.1, {
          range: [0.0001, 0.1],
          precision: 0.0001
        }),
        mouseInfluenceFactorFade: distExports.types.number(3, {
          range: [0.1, 3],
          precision: 0.1
        })
      }
    );
  }

  /**
   * Setup Theatre.js controls for interaction plane transform
   */
  setupInteractionPlaneControls() {
    if (!this.params.theatreSheet || !this.interactionPlane) {
      return
    }

    // Theatre.js controls for Interaction Plane Transform
    this.interactionPlaneTransformObject = this.params.theatreSheet.object(
      'Interaction Plane - Transform',
      {
        positionX: distExports.types.number(this.interactionPlane.position.x, {
          range: [-10, 10],
          precision: 0.01
        }),
        positionY: distExports.types.number(this.interactionPlane.position.y, {
          range: [-10, 10],
          precision: 0.01
        }),
        positionZ: distExports.types.number(this.interactionPlane.position.z, {
          range: [-10, 10],
          precision: 0.01
        }),
        rotationX: distExports.types.number(this.interactionPlane.rotation.x, {
          range: [-Math.PI, Math.PI],
          precision: 0.01
        }),
        rotationY: distExports.types.number(this.interactionPlane.rotation.y, {
          range: [-Math.PI, Math.PI],
          precision: 0.01
        }),
        rotationZ: distExports.types.number(this.interactionPlane.rotation.z, {
          range: [-Math.PI, Math.PI],
          precision: 0.01
        })
      }
    );

    // Listen to transform changes
    this.interactionPlaneTransformObject.onValuesChange((values) => {
      this.interactionPlane.position.set(
        values.positionX,
        values.positionY,
        values.positionZ
      );
      this.interactionPlane.rotation.set(
        values.rotationX,
        values.rotationY,
        values.rotationZ
      );
    });
  }

  /**
   * Handle mouse move events from worker dispatcher
   */
  handleMouseMove(event) {
    if (!this.params.camera || !this.interactionPlane) return

    // Respect the Theatre.js enabled toggle — treat as a forced leave when disabled
    if (!this.mouseInteractionObject?.value?.enabled) {
      if (this.isMouseOnPlane) {
        this.isMouseOnPlane = false;
        this.animateMouseInfluenceFade(0.0);
        if (this._rockSoundEnterTimeout) {
          clearTimeout(this._rockSoundEnterTimeout);
          this._rockSoundEnterTimeout = null;
        } else if (this._rockSoundsActive) {
          this._rockSoundsActive = false;
          dispatcherSingleton.trigger({ name: 'pauseSound' }, { soundId: 'rockOpenedLoop' });
          const index = Math.floor(Math.random() * 5) + 1;
          dispatcherSingleton.trigger({ name: 'playSound' }, { soundId: `rockRetract${index}` });
        }
      }
      return
    }

    // Calculate mouse position in normalized device coordinates (-1 to +1)
    // In worker context, we get clientX/clientY from the message
    this.mouse.x = (event.clientX / this.canvasWidth) * 2 - 1;
    this.mouse.y = -(event.clientY / this.canvasHeight) * 2 + 1;

    // Update raycaster
    this.raycaster.setFromCamera(this.mouse, this.params.camera);

    // Check intersection with the interaction plane
    const intersects = this.raycaster.intersectObject(this.interactionPlane);

    const wasOnPlane = this.isMouseOnPlane;

    if (intersects.length > 0) {
      this.mouseWorldPosition.copy(intersects[0].point);
      this.isMouseOnPlane = true;

      // Animate fade in when mouse first enters the plane
      if (!wasOnPlane) {
        this.animateMouseInfluenceFade(1.0);
        this._rockSoundEnterTimeout = setTimeout(() => {
          this._rockSoundEnterTimeout = null;
          this._rockSoundsActive = true;
          this._playRockEnterSounds();
        }, 200);
      }

      // Update debug sphere position
      if (this.debugSphere) {
        this.debugSphere.position.copy(this.mouseWorldPosition);
      }
    } else {
      this.isMouseOnPlane = false;

      // Animate fade out when mouse exits the plane
      if (wasOnPlane) {
        this.animateMouseInfluenceFade(0.0);
        if (this._rockSoundEnterTimeout) {
          clearTimeout(this._rockSoundEnterTimeout);
          this._rockSoundEnterTimeout = null;
        } else if (this._rockSoundsActive) {
          this._rockSoundsActive = false;
          dispatcherSingleton.trigger({ name: 'pauseSound' }, { soundId: 'rockOpenedLoop' });
          const index = Math.floor(Math.random() * 5) + 1;
          dispatcherSingleton.trigger({ name: 'playSound' }, { soundId: `rockRetract${index}` });
        }
      }
    }
  }

  /**
   * Animate mouse influence fade with GSAP
   */
  animateMouseInfluenceFade(targetValue) {
    // Get fade duration from Theatre.js settings (in seconds)
    const mouseValues = this.mouseInteractionObject?.value;
    const fadeDuration = mouseValues?.mouseInfluenceFactorFade || 0.5;

    // Kill any existing tween
    if (this.mouseInfluenceFadeTween) {
      this.mouseInfluenceFadeTween.kill();
    }

    // Create new tween with power2.out easing for smooth fade
    this.mouseInfluenceFadeTween = gsapWithCSS.to(this, {
      mouseInfluenceFade: targetValue,
      duration: fadeDuration,
      ease: 'power2.out'
    });
  }

  /**
   * Play a random rock extend sound and start the opened loop on mouse enter
   */
  _playRockEnterSounds() {
    const index = Math.floor(Math.random() * 5) + 1;
    dispatcherSingleton.trigger({ name: 'playSound' }, { soundId: `rockExtend${index}` });
    dispatcherSingleton.trigger({ name: 'playSound' }, { soundId: 'rockOpenedLoop' });
  }

  /**
   * Handle resize events to update canvas dimensions
   */
  handleResize(data) {
    this.canvasWidth = data.width;
    this.canvasHeight = data.height;
  }

  /**
   * Handle scene UI visibility changes to enable/disable mouse tracking
   */
  handleSceneUiVisibilityChanged(data) {
    if (this.firstLoad) return
    if (data.section === 'sectionIntro') {
      const isActive = data.visible;

      if (isActive) {
        this.firstLoad = true;
        this.enableMouseTracking();
      }
    }
  }

  /**
   * Handle scene UI visibility changes to enable/disable mouse tracking
   */
  handleSceneVisibilityChanged(data) {
    if (data.section === 'sectionIntro') {
      const isActive = data.visible;

      if (isActive) {
        this.enableMouseTracking();
      } else {
        this.disableMouseTracking();
      }
    }
  }

  /**
   * Enable mouse tracking via dispatcher (worker-compatible)
   */
  enableMouseTracking() {
    // Avoid adding duplicate listeners
    if (this.isMouseTrackingEnabled) {
      return
    }

    // Initialize canvas size from store if available
    if (store.canvasSize) {
      this.canvasWidth = store.canvasSize.width;
      this.canvasHeight = store.canvasSize.height;
    }

    // Listen to pointermove events from the dispatcher
    dispatcherSingleton.on('pointermove', this.onMouseMove);
    dispatcherSingleton.on('resize', this.onResize);

    this.isMouseTrackingEnabled = true;
  }

  /**
   * Disable mouse tracking
   */
  disableMouseTracking() {
    // Check if already disabled
    if (!this.isMouseTrackingEnabled) {
      return
    }

    // Remove event listeners from dispatcher
    dispatcherSingleton.off('pointermove', this.onMouseMove);
    dispatcherSingleton.off('resize', this.onResize);

    // Cancel any pending rock sound enter debounce
    if (this._rockSoundEnterTimeout) {
      clearTimeout(this._rockSoundEnterTimeout);
      this._rockSoundEnterTimeout = null;
    }
    this._rockSoundsActive = false;

    // Kill any active fade tween
    if (this.mouseInfluenceFadeTween) {
      this.mouseInfluenceFadeTween.kill();
      this.mouseInfluenceFadeTween = null;
    }

    // Reset blocks to original positions
    this.resetBlockPositions();

    this.isMouseTrackingEnabled = false;
  }

  /**
   * Reset all block positions to their original positions
   * Clears the mouse displacement for smooth return to original state
   */
  resetBlockPositions() {
    if (this.spireBlocks.length === 0) return

    // Reset mouse displacement and mesh positions for all blocks
    this.spireBlocks.forEach((blockData) => {
      const {
        mesh,
        originalPosition,
        currentMouseDisplacement,
        smoothedPosition
      } = blockData;

      // Clear the displacement vector
      currentMouseDisplacement.set(0, 0, 0);

      // Reset smoothed position to original
      smoothedPosition.copy(originalPosition);

      // Immediately reset mesh to original position
      // Note: Floating animation (if enabled) will still apply on next update
      mesh.position.copy(originalPosition);
    });

    // Reset mouse on plane state
    this.isMouseOnPlane = false;
  }

  /**
   * Apply environment map to model materials
   */
  applyEnvironmentMap(envRenderTarget) {
    if (!envRenderTarget || !this.model) return

    const envMap = envRenderTarget.texture;

    // Track materials we've explicitly handled
    const handledMaterials = new Set();

    // Apply to Spire Blocks / Material
    if (this.materials['Spire.002']) {
      this.materials['Spire.002'].envMap = envMap;
      this.materials['Spire.002'].needsUpdate = true;
      handledMaterials.add(this.materials['Spire.002']);
    }

    // Apply to all other materials in the model
    this.model.traverse((child) => {
      if (
        child.isMesh &&
        child.material &&
        !handledMaterials.has(child.material)
      ) {
        child.material.envMap = envMap;
        child.material.needsUpdate = true;
      }
    });
  }

  /**
   * Static factory method for async creation
   */
  static async create(params) {
    const mainModel = new MainModel(params);
    await mainModel.create();
    return mainModel
  }

  /**
   * Get the THREE.js model object
   */
  getModel() {
    return this.model
  }

  /**
   * Get the imported camera target
   */
  getCameraTarget() {
    return this.importedCameraTarget
  }

  /**
   * Get material references
   */
  getMaterials() {
    return this.materials
  }

  /**
   * Set model position
   */
  setPosition(x, y, z) {
    if (this.model) {
      this.model.position.set(x, y, z);
    }
  }

  /**
   * Set model scale
   */
  setScale(x, y, z) {
    if (this.model) {
      this.model.scale.set(x, y, z);
    }
  }

  /**
   * Update method - call this in your render loop
   * @param {number} deltaTime - Time elapsed since last frame in seconds
   */
  update(deltaTime = 0.016) {
    // Update time
    this.time += deltaTime;

    // Keep mask noise animated
    if (this.maskTime) {
      this.maskTime.value = this.time;
    }

    if (this.spireBlocks.length === 0) {
      return
    }

    // Get animation values
    const mainSceneValues = this.params.mainSceneObject?.value;
    const floatingValues = this.floatingAnimationObject?.value;
    const mouseValues = this.mouseInteractionObject?.value;

    // Mouse influence fade is now handled by GSAP in handleMouseMove
    // Just ensure it's 0 if mouse interaction is disabled
    if (!mouseValues?.enabled) {
      this.mouseInfluenceFade = 0;
      if (this.mouseInfluenceFadeTween) {
        this.mouseInfluenceFadeTween.kill();
        this.mouseInfluenceFadeTween = null;
      }
    }

    const centerPoint = new Vector3(
      floatingValues?.centerX || 0,
      floatingValues?.centerY || 0,
      floatingValues?.centerZ || 0
    );

    // Animate each block
    this.spireBlocks.forEach((blockData) => {
      const {
        mesh,
        originalPosition,
        timeOffset,
        currentMouseDisplacement,
        smoothedPosition
      } = blockData;

      // Calculate direction from center to original position
      const direction = new Vector3().subVectors(
        originalPosition,
        centerPoint
      );

      // Store the horizontal and vertical scale factors for later use
      const horizontalScale = floatingValues?.horizontalScale || 1.0;
      const verticalScale = floatingValues?.verticalScale || 1.0;
      const cornerScale = floatingValues?.cornerScale || 0.7;

      // Calculate how "horizontal" vs "vertical" this block is from center
      const totalLength = direction.length();
      const horizontalLength = Math.sqrt(
        direction.x * direction.x + direction.z * direction.z
      );
      const verticalLength = Math.abs(direction.y);

      // Normalize components (0-1 range)
      const horizontalRatio =
        totalLength > 0 ? horizontalLength / totalLength : 0;
      const verticalRatio = totalLength > 0 ? verticalLength / totalLength : 0;

      // Calculate how "diagonal" this block is (1.0 = perfectly diagonal, 0.0 = purely horizontal or vertical)
      // When both ratios are similar, the block is at a corner/diagonal position
      const ratioDifference = Math.abs(horizontalRatio - verticalRatio);
      const diagonalness = 1.0 - ratioDifference; // 1.0 when ratios are equal, 0.0 when one is 0

      // Calculate base distance scale factor based on angle
      // Blocks to the left/right get horizontalScale, blocks above/below get verticalScale
      const baseDistanceScale =
        horizontalRatio * horizontalScale + verticalRatio * verticalScale;

      // Apply corner scale factor for diagonal blocks
      // Smoothly blend between baseDistanceScale and cornerScale based on diagonalness
      const distanceScaleFactor =
        baseDistanceScale * (1.0 - diagonalness) +
        cornerScale * baseDistanceScale * diagonalness;

      // Normalize direction without changing its angle
      direction.normalize();

      // If the block is at the exact center point, use a default direction
      if (direction.length() === 0) {
        direction.set(0, 1, 0);
      }

      // Start with original position
      let finalPosition = originalPosition.clone();

      // Apply mouse interaction if enabled (do this FIRST)
      if (mouseValues?.enabled && this.isMouseOnPlane) {
        // Update debug influence circle
        if (this.debugInfluenceCircle && blockData === this.spireBlocks[0]) {
          this.debugInfluenceCircle.visible = true;
          this.debugInfluenceCircle.position.copy(this.mouseWorldPosition);
          this.debugInfluenceCircle.rotation.copy(
            this.interactionPlane.rotation
          );

          // Scale to show influence radius
          const scale = mouseValues.influenceRadius;
          this.debugInfluenceCircle.scale.set(scale, scale, scale);
        }

        // Get block's world position for accurate distance calculation
        const blockWorldPosition = new Vector3();
        mesh.getWorldPosition(blockWorldPosition);

        // Calculate distance from mouse position to this block's position (in world space)
        const distanceToMouse = blockWorldPosition.distanceTo(
          this.mouseWorldPosition
        );

        // Calculate influence based on distance with falloff
        const influenceRadius = mouseValues.influenceRadius;

        // Calculate target displacement
        let targetDisplacement = new Vector3(0, 0, 0);

        if (distanceToMouse < influenceRadius) {
          // Calculate normalized influence (1.0 at mouse position, 0.0 at radius edge)
          const normalizedDistance = distanceToMouse / influenceRadius;

          // Apply falloff curve (higher falloffPower = sharper falloff)
          const influence = Math.pow(
            1.0 - normalizedDistance,
            mouseValues.falloffPower
          );

          // Calculate push strength - closer to mouse = stronger push
          // Apply distance scale factor based on whether block is horizontal or vertical
          const pushAmount =
            influence * mouseValues.pushStrength * distanceScaleFactor;

          // Push away from center point (use the already calculated direction)
          const pushDirection = direction.clone();

          // If at center, use direction away from mouse
          if (pushDirection.length() === 0) {
            pushDirection
              .subVectors(originalPosition, this.mouseWorldPosition)
              .normalize();
          }

          // Calculate target displacement
          targetDisplacement = pushDirection.multiplyScalar(pushAmount);
        }

        // Smooth interpolation using lerp
        const smoothingFactor = mouseValues.smoothing;
        currentMouseDisplacement.lerp(targetDisplacement, smoothingFactor);

        // Apply the smoothed displacement with influence factor and fade
        const mouseInfluenceFactor =
          (mainSceneValues?.mouseInfluenceFactor ?? 1.0) *
          this.mouseInfluenceFade;
        const scaledDisplacement = currentMouseDisplacement
          .clone()
          .multiplyScalar(mouseInfluenceFactor);
        finalPosition.add(scaledDisplacement);
      } else {
        // When disabled or mouse not on plane, smoothly return to original position
        if (mouseValues?.enabled) {
          const smoothingFactor = mouseValues.smoothing;
          currentMouseDisplacement.lerp(
            new Vector3(0, 0, 0),
            smoothingFactor
          );
          // Apply the smoothed displacement with influence factor and fade
          const mouseInfluenceFactor =
            (mainSceneValues?.mouseInfluenceFactor ?? 1.0) *
            this.mouseInfluenceFade;
          const scaledDisplacement = currentMouseDisplacement
            .clone()
            .multiplyScalar(mouseInfluenceFactor);
          finalPosition.add(scaledDisplacement);
        }

        if (this.debugInfluenceCircle) {
          this.debugInfluenceCircle.visible = false;
        }
      }

      // Apply floating animation if enabled (do this AFTER mouse interaction so noise is always visible)
      if (floatingValues?.enabled) {
        // Calculate amplification factor based on mouse displacement
        // The more the block is pushed, the more pronounced the noise becomes
        // Scale by mouseInfluenceFactor and fade so amplification is controlled too
        const mouseInfluenceFactor =
          (mainSceneValues?.mouseInfluenceFactor ?? 1.0) *
          this.mouseInfluenceFade;
        const effectiveDisplacement =
          currentMouseDisplacement.length() * mouseInfluenceFactor;
        const amplificationFactor = 1.0 + effectiveDisplacement * 100; // Increase noise by 50% per unit of displacement

        // Base animation - smooth sine wave (remapped to 0-1 range for outward-only motion)
        const basePhase = this.time * floatingValues.floatSpeed + timeOffset;
        const baseAnimation = (Math.sin(basePhase) + 1) / 2; // Remap from [-1,1] to [0,1]

        // Noise overlay using multiple sine waves at different frequencies
        const noisePhase = this.time * floatingValues.noiseSpeed + timeOffset;
        const noise1 = Math.sin(
          noisePhase * floatingValues.noiseFrequency * 1.0
        );
        // const noise2 = Math.sin(
        //   noisePhase * floatingValues.noiseFrequency * 2.3 + 1.5
        // );
        // const noise3 = Math.sin(
        //   noisePhase * floatingValues.noiseFrequency * 4.7 + 3.8
        // );
        const combinedNoise = noise1;

        // Combine base animation with noise and apply amplification
        const noiseModulation = Math.abs(
          combinedNoise * floatingValues.noiseAmplitude
        ); // Absolute value for outward-only
        const finalAnimation = baseAnimation + noiseModulation;

        // Calculate the offset distance (always positive = always outward)
        // Apply distance scale factor for horizontal vs vertical distances
        const offsetDistance =
          finalAnimation *
          floatingValues.floatDistance *
          amplificationFactor *
          distanceScaleFactor;

        // Apply position offset along the direction
        finalPosition.add(direction.clone().multiplyScalar(offsetDistance));
      }

      // Constrain final position to maximum travel distance from original position
      const maxTravelDistance = floatingValues?.maxTravelDistance || 2.0;
      const travelVector = new Vector3().subVectors(
        finalPosition,
        originalPosition
      );
      const travelDistance = travelVector.length();

      if (travelDistance > maxTravelDistance) {
        // Clamp the position to be within maxTravelDistance
        travelVector.normalize().multiplyScalar(maxTravelDistance);
        finalPosition.copy(originalPosition).add(travelVector);
      }

      // Apply final position smoothing for extra smooth movement
      const positionSmoothingFactor = floatingValues?.positionSmoothing || 0.15;
      smoothedPosition.lerp(finalPosition, positionSmoothingFactor);

      // Set final smoothed position
      mesh.position.copy(smoothedPosition);
    });
  }

  /**
   * Dispose resources
   */
  dispose() {
    // Kill any active fade tween
    if (this.mouseInfluenceFadeTween) {
      this.mouseInfluenceFadeTween.kill();
      this.mouseInfluenceFadeTween = null;
    }

    // Remove scene visibility event listener
    if (this.onSceneUiVisibilityChanged) {
      dispatcherSingleton.off(
        'sceneUIVisibilityChanged',
        this.onSceneUiVisibilityChanged
      );
      this.onSceneUiVisibilityChanged = null;
    }

    if (this.onSceneVisibilityChanged) {
      dispatcherSingleton.off('sceneVisibilityChanged', this.onSceneVisibilityChanged);
      this.onSceneVisibilityChanged = null;
    }

    // Remove mouse event listeners
    this.disableMouseTracking();

    // Dispose debug sphere
    if (this.debugSphere) {
      this.params.scene.remove(this.debugSphere);
      this.debugSphere.geometry.dispose();
      this.debugSphere.material.dispose();
      this.debugSphere = null;
    }

    // Dispose debug influence circle
    if (this.debugInfluenceCircle) {
      this.params.scene.remove(this.debugInfluenceCircle);
      this.debugInfluenceCircle.geometry.dispose();
      this.debugInfluenceCircle.material.dispose();
      this.debugInfluenceCircle = null;
    }

    // Dispose interaction plane
    if (this.interactionPlane) {
      this.params.scene.remove(this.interactionPlane);
      this.interactionPlane.geometry.dispose();
      this.interactionPlane.material.dispose();
      this.interactionPlane = null;
    }

    if (this.model) {
      this.params.scene.remove(this.model);

      // Dispose geometries and materials
      this.model.traverse((child) => {
        if (child.isMesh) {
          if (child.geometry) {
            child.geometry.dispose();
          }
          if (child.material) {
            if (Array.isArray(child.material)) {
              child.material.forEach((mat) => mat.dispose());
            } else {
              child.material.dispose();
            }
          }
        }
      });

      this.model = null;
    }

    this.materials = {};
    this.importedCameraTarget = null;
  }
}

/**
 * BoxParticles - Global particle system with particles randomly distributed in an adjustable box
 *
 * Similar to MeshParticles but without mesh sampling. Particles are randomly distributed
 * in a 3D box volume with configurable dimensions.
 */
class BoxParticles {
  constructor(renderer, params = {}, bubblesTexture = null) {
    this.renderer = renderer;
    this.bubblesTexture = bubblesTexture;

    this.params = {
      particleCount: 1000,
      particleSize: 5.0,
      sizeVariation: 3.0,
      // Box dimensions (for particle distribution)
      boxWidth: 10.0,
      boxHeight: 10.0,
      boxDepth: 10.0,
      // Scan effect
      scanSize: 0.175,
      scanDirection: 0, // 0 = vertical (Y), 1 = horizontal (X)
      // Curl noise
      curlFrequency: 5.0,
      curlAmplitude: 0.1,
      curlSpeed: 0.2,
      // Influence point
      influencePointX: 0.0,
      influencePointY: 0.0,
      influencePointZ: 0.0,
      influenceRadius: 0.3,
      influenceIntensity: 1.0,
      // Color controls
      colorOverlayR: 1.0,
      colorOverlayG: 1.0,
      colorOverlayB: 1.0,
      colorOverlayBlendMode: 0, // 0=multiply, 1=add, 2=overlay, 3=screen
      colorOverlayStrength: 0.0,
      saturation: 1.0,
      contrast: 1.0,
      brightness: 1.0,
      minBrightness: 0.0,
      ...params
    };

    this.particles = null;
    this.particleUniforms = null;
    this.group = new Group(); // Use a group for positioning
  }

  /**
   * Initialize the particle system
   */
  async init() {
    const particleData = this.generateParticleData();
    this._createParticleSystem(particleData);
  }

  /**
   * Generate random particle data distributed in a box
   */
  generateParticleData() {
    const count = this.params.particleCount;

    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);
    const sizes = new Float32Array(count);
    const initialPositions = new Float32Array(count * 3);
    const mouseResponsive = new Float32Array(count);
    const spriteVariations = new Float32Array(count);
    const brightnesses = new Float32Array(count);

    const halfWidth = this.params.boxWidth * 0.5;
    const halfHeight = this.params.boxHeight * 0.5;
    const halfDepth = this.params.boxDepth * 0.5;

    for (let i = 0; i < count; i++) {
      const i3 = i * 3;

      // Random position within box (centered at origin, group position will offset)
      const x = (Math.random() * 2 - 1) * halfWidth;
      const y = (Math.random() * 2 - 1) * halfHeight;
      const z = (Math.random() * 2 - 1) * halfDepth;

      const r = 1.0;
      const g = 1.0;
      const b = 1.0;

      const sizeMultiplier =
        1.0 + (Math.random() * 2 - 1) * this.params.sizeVariation;

      const brightness = 0.8 + Math.random() * 0.2;

      const isMouseResponsive = 0.0;

      const spriteVariation = Math.floor(Math.random() * 7);

      positions[i3 + 0] = x;
      positions[i3 + 1] = y;
      positions[i3 + 2] = z;

      initialPositions[i3 + 0] = x;
      initialPositions[i3 + 1] = y;
      initialPositions[i3 + 2] = z;

      colors[i3 + 0] = r;
      colors[i3 + 1] = g;
      colors[i3 + 2] = b;

      sizes[i] = sizeMultiplier;

      mouseResponsive[i] = isMouseResponsive;
      spriteVariations[i] = spriteVariation;
      brightnesses[i] = brightness;
    }

    return {
      positions,
      colors,
      sizes,
      initialPositions,
      mouseResponsive,
      spriteVariations,
      brightnesses,
      count
    }
  }

  /**
   * Create the particle system from generated data using sprite-based rendering
   */
  _createParticleSystem(particleData) {
    const maxCount = particleData.count;

    // Pack into 4 vec4 buffers
    const packedA1 = new Float32Array(maxCount * 4);
    const packedA2 = new Float32Array(maxCount * 4);
    const packedA3 = new Float32Array(maxCount * 4);
    const packedA4 = new Float32Array(maxCount * 4);

    for (let i = 0; i < maxCount; i++) {
      const i3 = i * 3;
      const i4 = i * 4;

      // Pack A1: initialX, initialY, initialZ, unused
      packedA1[i4 + 0] = particleData.initialPositions[i3 + 0];
      packedA1[i4 + 1] = particleData.initialPositions[i3 + 1];
      packedA1[i4 + 2] = particleData.initialPositions[i3 + 2];
      packedA1[i4 + 3] = 0;

      // Pack A2: colorR, colorG, colorB, size
      packedA2[i4 + 0] = particleData.colors[i3 + 0];
      packedA2[i4 + 1] = particleData.colors[i3 + 1];
      packedA2[i4 + 2] = particleData.colors[i3 + 2];
      packedA2[i4 + 3] = particleData.sizes[i];

      // Pack A3: unused
      packedA3[i4 + 0] = 0;
      packedA3[i4 + 1] = 0;
      packedA3[i4 + 2] = 0;
      packedA3[i4 + 3] = 0;

      // Pack A4: spriteVariation+mouseResponsive*10, brightness, reserved, reserved
      packedA4[i4 + 0] =
        particleData.spriteVariations[i] +
        particleData.mouseResponsive[i] * 10.0;
      packedA4[i4 + 1] = particleData.brightnesses[i]; // All particles affected by curl
      packedA4[i4 + 2] = 0;
      packedA4[i4 + 3] = 0;
    }

    const packedA1Attr = new InstancedBufferAttribute(packedA1, 4);
    packedA1Attr.setUsage(DynamicDrawUsage);
    const packedA2Attr = new InstancedBufferAttribute(packedA2, 4);
    packedA2Attr.setUsage(DynamicDrawUsage);
    const packedA3Attr = new InstancedBufferAttribute(packedA3, 4);
    packedA3Attr.setUsage(DynamicDrawUsage);
    const packedA4Attr = new InstancedBufferAttribute(packedA4, 4);
    packedA4Attr.setUsage(DynamicDrawUsage);

    // Configure bubble sprite sheet texture
    const bubbleSpriteSheet = this.bubblesTexture;
    if (bubbleSpriteSheet) {
      bubbleSpriteSheet.minFilter = LinearFilter;
      bubbleSpriteSheet.magFilter = LinearFilter;
      bubbleSpriteSheet.colorSpace = LinearSRGBColorSpace;
      bubbleSpriteSheet.needsUpdate = true;
    }

    // Create sprite material with instanced attributes
    const material = new SpriteNodeMaterial({
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
      map: bubbleSpriteSheet
    });

    // Create uniforms
    const uTime = uniform(0);
    const uProgress = uniform(0);
    const uScanSize = uniform(this.params.scanSize);
    const uScanDirection = uniform(this.params.scanDirection);
    const uParticleSize = uniform(this.params.particleSize);
    const uCurlFrequency = uniform(this.params.curlFrequency || 5.0);
    const uCurlAmplitude = uniform(this.params.curlAmplitude || 0.1);
    const uCurlSpeed = uniform(this.params.curlSpeed || 0.2);
    const uInfluencePoint = uniform(
      vec3(
        this.params.influencePointX || 0.0,
        this.params.influencePointY || 0.0,
        this.params.influencePointZ || 0.0
      )
    );
    const uInfluenceRadius = uniform(this.params.influenceRadius || 0.3);
    const uInfluenceIntensity = uniform(this.params.influenceIntensity || 1.0);
    const uColorOverlay = uniform(
      vec3(
        this.params.colorOverlayR || 1.0,
        this.params.colorOverlayG || 1.0,
        this.params.colorOverlayB || 1.0
      )
    );
    const uColorOverlayBlendMode = uniform(
      this.params.colorOverlayBlendMode || 0
    );
    const uColorOverlayStrength = uniform(
      this.params.colorOverlayStrength || 0.0
    );
    const uSaturation = uniform(this.params.saturation || 1.0);
    const uContrast = uniform(this.params.contrast || 1.0);
    const uBrightness = uniform(this.params.brightness || 1.0);
    const uMinBrightness = uniform(this.params.minBrightness || 0.0);

    // Create instanced buffer attribute references
    const attrA1 = instancedBufferAttribute(packedA1Attr);
    const attrA2 = instancedBufferAttribute(packedA2Attr);
    instancedBufferAttribute(packedA3Attr);
    const attrA4 = instancedBufferAttribute(packedA4Attr);

    // Unpack attributes
    const particleInitialPositions = vec3(attrA1.x, attrA1.y, attrA1.z);
    const particleColors = vec3(attrA2.x, attrA2.y, attrA2.z);
    const particleSizes = attrA2.w;

    const spriteAndMouse = attrA4.x;
    const particleSpriteVariations = spriteAndMouse.mod(7.0);

    const particleBrightnesses = attrA4.y; // All particles affected by curl

    // Position node
    material.positionNode = Fn(() => {
      const initialPos = particleInitialPositions.toVar();
      const pos = initialPos.toVar();

      // Curl noise
      const distToInfluence = length(pos.sub(uInfluencePoint));
      const influenceFactor = float(1.0).sub(
        smoothstep(float(0.0), uInfluenceRadius, distToInfluence)
      );
      const curlReduction = float(1.0).sub(
        influenceFactor.mul(uInfluenceIntensity)
      );
      const effectiveCurlAmplitude = uCurlAmplitude.mul(curlReduction);

      const curlOffset = rt(
        vec3(pos.x, pos.y, uTime.mul(uCurlSpeed.mul(0.01))),
        uCurlFrequency,
        uTime.mul(uCurlSpeed).mul(0.01),
        effectiveCurlAmplitude,
        false
      );

      // Apply curl to all particles
      pos.x.addAssign(curlOffset.x);
      pos.y.addAssign(curlOffset.y);
      pos.z.addAssign(curlOffset.z.mul(0.1));

      return pos
    })();

    // Scale node
    material.scaleNode = Fn(() => {
      const baseScale = uParticleSize.mul(particleSizes).mul(0.01);
      return baseScale
    })();

    // Sprite sheet texture node
    const tBubbleSprite = texture(bubbleSpriteSheet);

    // Color adjustment functions
    const adjustSaturation = Fn(([color, saturation]) => {
      const gray = color.dot(vec3(0.299, 0.587, 0.114));
      return mix(vec3(gray), color, saturation)
    });

    const adjustContrast = Fn(([color, contrast]) => {
      return color.sub(0.5).mul(contrast).add(0.5)
    });

    const adjustBrightness = Fn(([color, brightness]) => {
      return color.mul(brightness)
    });

    const applyMinBrightness = Fn(([color, minBrightness]) => {
      const luminance = color.dot(vec3(0.299, 0.587, 0.114));
      const brightnessFactor = luminance
        .max(minBrightness)
        .div(luminance.add(0.0001));
      return color.mul(brightnessFactor)
    });

    const blendMultiply = Fn(([base, overlay]) => {
      return base.mul(overlay)
    });

    const blendAdd = Fn(([base, overlay]) => {
      return base.add(overlay).min(1.0)
    });

    const blendOverlay = Fn(([base, overlay]) => {
      const condition = base.lessThan(0.5);
      const multiply = base.mul(overlay).mul(2.0);
      const screen = float(1.0).sub(
        float(1.0).sub(base).mul(float(1.0).sub(overlay)).mul(2.0)
      );
      return mix(screen, multiply, condition)
    });

    const blendScreen = Fn(([base, overlay]) => {
      return float(1.0).sub(float(1.0).sub(base).mul(float(1.0).sub(overlay)))
    });

    const applyColorOverlay = Fn(
      ([baseColor, overlayColor, blendMode, strength]) => {
        let blended = baseColor.toVar();
        const isMultiply = blendMode.lessThan(0.5);
        const isAdd = blendMode
          .greaterThanEqual(0.5)
          .and(blendMode.lessThan(1.5));
        const isOverlay = blendMode
          .greaterThanEqual(1.5)
          .and(blendMode.lessThan(2.5));
        const isScreen = blendMode.greaterThanEqual(2.5);

        const multiply = blendMultiply(baseColor, overlayColor);
        const add = blendAdd(baseColor, overlayColor);
        const overlay = blendOverlay(baseColor, overlayColor);
        const screen = blendScreen(baseColor, overlayColor);

        blended.assign(mix(blended, multiply, isMultiply));
        blended.assign(mix(blended, add, isAdd));
        blended.assign(mix(blended, overlay, isOverlay));
        blended.assign(mix(blended, screen, isScreen));

        return mix(baseColor, blended, strength)
      }
    );

    // Color node
    material.colorNode = Fn(() => {
      const col = particleColors;
      const initialPos = particleInitialPositions.toVar();

      const scanPosition = uProgress.mul(2).sub(1);
      const worldPos = mix(initialPos.y, initialPos.x, uScanDirection);
      const distanceToScan = abs(worldPos.sub(scanPosition));
      const scanMask = smoothstep(uScanSize, 0.0, distanceToScan);

      const glowColor = vec3(0.5, 0.7, 1.0);
      let finalColor = mix(col, glowColor, scanMask.mul(0.6)).toVar();

      finalColor.mulAssign(particleBrightnesses);

      const spriteUV = uv().toVar();
      const spriteWidth = float(1.0 / 7.0);
      spriteUV.x.assign(
        spriteUV.x
          .mul(spriteWidth)
          .add(particleSpriteVariations.mul(spriteWidth))
      );

      const spriteTexel = tBubbleSprite.sample(spriteUV);

      const baseAlpha = mix(float(1), float(1.0), scanMask).mul(
        particleBrightnesses
      );

      let mixedColor = finalColor.mul(spriteTexel.rgb).toVar();

      // Apply color controls
      mixedColor.assign(
        applyColorOverlay(
          mixedColor,
          uColorOverlay,
          uColorOverlayBlendMode,
          uColorOverlayStrength
        )
      );
      mixedColor.assign(adjustSaturation(mixedColor, uSaturation));
      mixedColor.assign(adjustContrast(mixedColor, uContrast));
      mixedColor.assign(adjustBrightness(mixedColor, uBrightness));
      mixedColor.assign(applyMinBrightness(mixedColor, uMinBrightness));
      mixedColor.assign(mixedColor.max(0.0).min(1.0));

      const alpha = baseAlpha.mul(spriteTexel.a);

      return vec4(mixedColor, alpha)
    })();

    // Create sprite
    this.particles = new Sprite(material);
    this.particles.count = maxCount;
    this.particles.frustumCulled = false;

    // Attach packed attributes
    this.particles.geometry.setAttribute('packedA1', packedA1Attr);
    this.particles.geometry.setAttribute('packedA2', packedA2Attr);
    this.particles.geometry.setAttribute('packedA3', packedA3Attr);
    this.particles.geometry.setAttribute('packedA4', packedA4Attr);

    this.particles.renderOrder = 1;

    // Add particles to group
    this.group.add(this.particles);

    // Store uniforms
    this.particleUniforms = {
      uTime,
      uProgress,
      uParticleSize,
      uScanSize,
      uScanDirection,
      uCurlFrequency,
      uCurlAmplitude,
      uCurlSpeed,
      uInfluencePoint,
      uInfluenceRadius,
      uInfluenceIntensity,
      uColorOverlay,
      uColorOverlayBlendMode,
      uColorOverlayStrength,
      uSaturation,
      uContrast,
      uBrightness,
      uMinBrightness
    };
  }

  /**
   * Update uniforms (call every frame)
   */
  updateUniforms(time, scanProgress = 0) {
    if (this.particleUniforms) {
      this.particleUniforms.uTime.value = time;
      this.particleUniforms.uParticleSize.value = this.params.particleSize;
      this.particleUniforms.uProgress.value = scanProgress;
      this.particleUniforms.uScanSize.value = this.params.scanSize;
      this.particleUniforms.uScanDirection.value = this.params.scanDirection;
      this.particleUniforms.uCurlFrequency.value =
        this.params.curlFrequency || 5.0;
      this.particleUniforms.uCurlAmplitude.value =
        this.params.curlAmplitude || 0.1;
      this.particleUniforms.uCurlSpeed.value = this.params.curlSpeed || 0.2;
      this.particleUniforms.uInfluencePoint.value.set(
        this.params.influencePointX || 0.0,
        this.params.influencePointY || 0.0,
        this.params.influencePointZ || 0.0
      );
      this.particleUniforms.uInfluenceRadius.value =
        this.params.influenceRadius || 0.3;
      this.particleUniforms.uInfluenceIntensity.value =
        this.params.influenceIntensity || 1.0;
      this.particleUniforms.uColorOverlay.value.set(
        this.params.colorOverlayR || 1.0,
        this.params.colorOverlayG || 1.0,
        this.params.colorOverlayB || 1.0
      );
      this.particleUniforms.uColorOverlayBlendMode.value =
        this.params.colorOverlayBlendMode || 0;
      this.particleUniforms.uColorOverlayStrength.value =
        this.params.colorOverlayStrength || 0.0;
      this.particleUniforms.uSaturation.value = this.params.saturation || 1.0;
      this.particleUniforms.uContrast.value = this.params.contrast || 1.0;
      this.particleUniforms.uBrightness.value = this.params.brightness || 1.0;
      this.particleUniforms.uMinBrightness.value =
        this.params.minBrightness || 0.0;
    }
  }

  /**
   * Update box dimensions and regenerate particles if needed
   * Position updates are handled by moving the group
   */
  updateBox(params = {}) {
    // Update params
    Object.assign(this.params, params);

    // Check if we need to regenerate particles (only for dimensions/count changes)
    const needsRegenerate =
      params.boxWidth !== undefined ||
      params.boxHeight !== undefined ||
      params.boxDepth !== undefined ||
      params.particleCount !== undefined;

    if (needsRegenerate && this.particles) {
      const particleData = this.generateParticleData();

      // Update packed attributes
      const maxCount = particleData.count;
      const packedA1 = new Float32Array(maxCount * 4);
      const packedA2 = new Float32Array(maxCount * 4);
      const packedA3 = new Float32Array(maxCount * 4);
      const packedA4 = new Float32Array(maxCount * 4);

      for (let i = 0; i < maxCount; i++) {
        const i3 = i * 3;
        const i4 = i * 4;

        packedA1[i4 + 0] = particleData.initialPositions[i3 + 0];
        packedA1[i4 + 1] = particleData.initialPositions[i3 + 1];
        packedA1[i4 + 2] = particleData.initialPositions[i3 + 2];
        packedA1[i4 + 3] = 0;

        packedA2[i4 + 0] = particleData.colors[i3 + 0];
        packedA2[i4 + 1] = particleData.colors[i3 + 1];
        packedA2[i4 + 2] = particleData.colors[i3 + 2];
        packedA2[i4 + 3] = particleData.sizes[i];

        packedA3[i4 + 0] = 0;
        packedA3[i4 + 1] = 0;
        packedA3[i4 + 2] = 0;
        packedA3[i4 + 3] = 0;

        packedA4[i4 + 0] =
          particleData.spriteVariations[i] +
          particleData.mouseResponsive[i] * 10.0;
        packedA4[i4 + 1] = particleData.brightnesses[i]; // All particles affected by curl
        packedA4[i4 + 2] = 0;
        packedA4[i4 + 3] = 0;
      }

      this.particles.geometry.attributes.packedA1.array = packedA1;
      this.particles.geometry.attributes.packedA2.array = packedA2;
      this.particles.geometry.attributes.packedA3.array = packedA3;
      this.particles.geometry.attributes.packedA4.array = packedA4;

      this.particles.geometry.attributes.packedA1.needsUpdate = true;
      this.particles.geometry.attributes.packedA2.needsUpdate = true;
      this.particles.geometry.attributes.packedA3.needsUpdate = true;
      this.particles.geometry.attributes.packedA4.needsUpdate = true;

      this.particles.count = maxCount;
    }
  }

  /**
   * Get particle group (use this to add to scene)
   */
  getObject() {
    return this.group
  }

  /**
   * Set group position
   */
  setPosition(x, y, z) {
    this.group.position.set(x, y, z);
  }

  /**
   * Get group position
   */
  getPosition() {
    return this.group.position
  }

  /**
   * Dispose resources
   */
  dispose(renderer) {
    if (!this.particles) return

    const geometry = this.particles.geometry;
    const material = this.particles.material;

    this.particles = null;
    this.particleUniforms = null;

    const device = renderer?.device ?? renderer?.backend?.device;

    if (device?.queue?.onSubmittedWorkDone) {
      device.queue.onSubmittedWorkDone().then(() => {
        geometry?.dispose?.();
        material?.dispose?.();
      });
    } else {
      setTimeout(() => {
        geometry?.dispose?.();
        material?.dispose?.();
      }, 0);
    }
  }
}

