      initialPositions[i3 + 1] = 0;
      initialPositions[i3 + 2] = 0;
      velocities[i3 + 0] = 0;
      velocities[i3 + 1] = 0;
      velocities[i3 + 2] = 0;
      timeOffsets[i] = 0;
      mouseResponsive[i] = 0;
      curlResponsive[i] = 0;
      spriteVariations[i] = 0;
      brightnesses[i] = 0;

